INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 1:1','Provérbios de Salomão, filho de Davi, rei de Israel.'),
('Proverbs 1:2','Para conhecer a sabedoria e a instrução; para entender as palavras da prudência;'),
('Proverbs 1:3','Para obter a instrução do entendimento; justiça, juízo e equidades;'),
('Proverbs 1:4','Para dar inteligência aos simples, conhecimento e bom senso aos jovens.'),
('Proverbs 1:5','O sábio ouvirá, e crescerá em conhecimento; o bom entendedor obterá sábios conselhos.'),
('Proverbs 1:6','Para entender provérbios e sua interpretação; as palavras dos sábios, e seus enigmas.'),
('Proverbs 1:7','O temor ao SENHOR é o principio do conhecimento; os tolos desprezam a sabedoria e a instrução.'),
('Proverbs 1:8','Filho meu, ouve a instrução de teu pai; e não abandones a doutrina de tua mãe.'),
('Proverbs 1:9','Porque serão um ornamento gracioso para tua cabeça; e colares para teu pescoço.'),
('Proverbs 1:10','Filho meu, se os pecadores tentarem te convencer, não te deixes influenciar.'),
('Proverbs 1:11','Se disserem: Vem conosco, vamos espiar derramamento de sangue; preparemos uma emboscada ao inocente sem razão.'),
('Proverbs 1:12','Vamos tragá-los vivos, como se fosse o mundo dos mortos; e inteiros, como os que descem à cova.'),
('Proverbs 1:13','Acharemos toda espécie de coisas valiosas, encheremos nossas casas de despojos.'),
('Proverbs 1:14','Lança tua sorte entre nós, compartilharemos todos de uma só bolsa.'),
('Proverbs 1:15','Filho meu, não sigas teu caminho com eles; desvia teu pé para longe de onde eles passarem;'),
('Proverbs 1:16','Porque os pés deles correm para o mal, e se apressam para derramar sangue.'),
('Proverbs 1:17','Certamente é inútil se estender a rede diante da vista de todas as aves;'),
('Proverbs 1:18','Porém estes estão esperando o derramamento de seu próprio sangue; e preparam emboscada para suas próprias almas.'),
('Proverbs 1:19','Assim são os caminhos de todo aquele que tem ganância pelo lucro desonesto; ela tomará a alma daqueles que a tem.'),
('Proverbs 1:20','A sabedoria grita pelas ruas; nas praças ela levanta sua voz.'),
('Proverbs 1:21','Ela clama nas encruzilhadas, onde passam muita gente; às entradas das portas, nas cidades ela diz suas mensagens:'),
('Proverbs 1:22','Até quando, ó tolos, amareis a tolice? E vós zombadores, desejareis a zombaria? E vós loucos, odiareis o conhecimento?'),
('Proverbs 1:23','Convertei-vos à minha repreensão; eis que vos derramarei meu espírito, e vos farei saber minhas palavras.'),
('Proverbs 1:24','Mas porque eu clamei, e recusastes; estendi minha mão, e não houve quem desse atenção,'),
('Proverbs 1:25','E rejeitastes todo o meu conselho, e não quisestes minha repreensão,'),
('Proverbs 1:26','Também eu rirei em vosso sofrimento, e zombarei, quando vier vosso medo.'),
('Proverbs 1:27','Quando vier vosso temor como tempestade, e a causa de vosso sofrimento como ventania, quando vier sobre vós a opressão e a angústia,'),
('Proverbs 1:28','Então clamarão a mim; porém eu não responderei; de madrugada me buscarão, porém não me acharão.'),
('Proverbs 1:29','Porque odiaram o conhecimento; e escolheram não temer ao SENHOR.'),
('Proverbs 1:30','Não concordaram com meu conselho, e desprezaram toda a minha repreensão.'),
('Proverbs 1:31','Por isso comerão do fruto do seu próprio caminho, e se fartarão de seus próprios conselhos.'),
('Proverbs 1:32','Pois o desvio dos tolos os matará, e a confiança dos loucos os destruirá.'),
('Proverbs 1:33','Porém aquele que me ouvir habitará em segurança, e estará tranquilo do temor do mal.'),
('Proverbs 2:1','Filho meu, se aceitares minhas palavras, e depositares em ti meus mandamentos,'),
('Proverbs 2:2','Para fazeres teus ouvidos darem atenção à sabedoria, e inclinares teu coração à inteligência;'),
('Proverbs 2:3','E se clamares à prudência, e à inteligência dirigires tua voz;'),
('Proverbs 2:4','Se tu a buscares como a prata, e a procurares como que a tesouros escondidos,'),
('Proverbs 2:5','Então entenderás o temor ao SENHOR, e acharás o conhecimento de Deus.'),
('Proverbs 2:6','Porque o SENHOR dá sabedoria; de sua boca vem o conhecimento e o entendimento.'),
('Proverbs 2:7','Ele reserva a boa sabedoria para os corretos; ele é escudo para os que andam em sinceridade.'),
('Proverbs 2:8','Para guardar os caminhos do juízo; e conservar os passos de seus santos.'),
('Proverbs 2:9','Então entenderás a justiça e o juízo, e a equidade; e todo bom caminho.'),
('Proverbs 2:10','Quando a sabedoria entrar em teu coração, e o conhecimento for agradável à tua alma.'),
('Proverbs 2:11','O bom senso te guardará, e o entendimento te preservará:'),
('Proverbs 2:12','- Para te livrar do mau caminho, e dos homens que falam perversidades;'),
('Proverbs 2:13','Que deixam as veredas da justiça para andarem pelos caminhos das trevas;'),
('Proverbs 2:14','Que se alegram em fazer o mal, e se enchem de alegria com as perversidades dos maus;'),
('Proverbs 2:15','Cujas veredas são distorcidas, e desviadas em seus percursos.'),
('Proverbs 2:16','- Para te livrar da mulher estranha, e da pervertida, que lisonjeia com suas palavras;'),
('Proverbs 2:17','Que abandona o guia de sua juventude, e se esquece do pacto de seu Deus.'),
('Proverbs 2:18','Porque sua casa se inclina para a morte, e seus caminhos para os mortos.'),
('Proverbs 2:19','Todos os que entrarem a ela, não voltarão mais; e não alcançarão os caminhos da vida.'),
('Proverbs 2:20','- Para andares no caminho dos bons, e te guardares nas veredas dos justos.'),
('Proverbs 2:21','Porque os corretos habitarão a terra; e os íntegros nela permanecerão.'),
('Proverbs 2:22','Porém os perversos serão cortados da terra, e os infiéis serão arrancados dela.'),
('Proverbs 3:1','Filho meu, não te esqueças de minha lei; e que teu coração guarde meus mandamentos.'),
('Proverbs 3:2','Porque te acrescentarão extensão de dias, e anos de vida e paz.'),
('Proverbs 3:3','Que a bondade e a fidelidade não te desamparem; amarra-as junto ao teu pescoço; escreve-as na tábua de teu coração.'),
('Proverbs 3:4','Então tu acharás graça e bom entendimento, aos olhos de Deus e dos homens.'),
('Proverbs 3:5','Confia no SENHOR com todo o teu coração; e não te apoies em teu próprio entendimento.'),
('Proverbs 3:6','Dá reconhecimento a ele em todas os teus caminhos; e ele endireitará tuas veredas.'),
('Proverbs 3:7','Não sejas sábio aos teus próprios olhos; teme ao SENHOR, e afasta-te do mal.'),
('Proverbs 3:8','Isto será remédio para teu corpo, e alívio para teus ossos.'),
('Proverbs 3:9','Honra ao SENHOR com teus bens, e com a primeira parte de toda a tua renda.'),
('Proverbs 3:10','E teus celeiros se encherão de fartura, e teus tanques transbordarão de vinho novo.'),
('Proverbs 3:11','Filho meu, não rejeites a correção do SENHOR, nem te desagrades de sua repreensão;'),
('Proverbs 3:12','Porque o SENHOR repreende a quem ele ama, assim como o pai ao filho, a quem ele quer bem.'),
('Proverbs 3:13','Bem-aventurado o homem que encontra sabedoria, e o homem que ganha conhecimento.'),
('Proverbs 3:14','Porque seu produto é melhor que o produto da prata; e seu valor, mais do que o do ouro fino.'),
('Proverbs 3:15','Ela é mais preciosa do que rubis; e tudo o que podes desejar não se pode comparar a ela.'),
('Proverbs 3:16','Extensão de dias há em sua mão direita; em sua esquerda riquezas e honra.'),
('Proverbs 3:17','Seus caminhos são caminhos agradáveis; e todas as suas veredas são paz.'),
('Proverbs 3:18','Ela é uma árvore de vida para os que dela pegam; e bem-aventurados são todos os que a retêm.'),
('Proverbs 3:19','O SENHOR com sabedoria fundou a terra; ele preparou os céus com a inteligência.'),
('Proverbs 3:20','Com seu conhecimento se fenderam os abismos, e as nuvens gotejam orvalho.'),
('Proverbs 3:21','Filho meu, que estes não se afastem de teus olhos; guarda a sabedoria e o bom-senso.'),
('Proverbs 3:22','Porque serão vida para tua alma, e graça para teu pescoço.'),
('Proverbs 3:23','Então andarás por teu caminho em segurança; e com teus pés não tropeçarás.'),
('Proverbs 3:24','Quando te deitares, não terás medo; tu deitarás, e teu sono será suave.'),
('Proverbs 3:25','Não temas o pavor repentino; nem da assolação dos perversos, quando vier.'),
('Proverbs 3:26','Porque o SENHOR será tua esperança; e ele guardará teus pés para que não sejam presos.'),
('Proverbs 3:27','Não detenhas o bem daqueles que possuem o direito, se tiveres em tuas mãos poder para o fazeres.'),
('Proverbs 3:28','Não digas a teu próximo: Vai, e volta depois , que amanhã te darei; se tu tiveres contigo o que ele te pede .'),
('Proverbs 3:29','Não planejes o mal contra teu próximo, pois ele mora tendo confiança em ti.'),
('Proverbs 3:30','Não brigues contra alguém sem motivo, se ele não fez mal contra ti.'),
('Proverbs 3:31','Não tenhas inveja do homem violento, nem escolhas seguir algum dos caminhos dele.'),
('Proverbs 3:32','Porque o SENHOR abomina os perversos; mas ele guarda o seu segredo com os justos.'),
('Proverbs 3:33','A maldição do SENHOR está na casa do perverso; porém ele abençoa a morada dos justos.'),
('Proverbs 3:34','Certamente ele zombará dos zombadores; mas dará graça aos humildes.'),
('Proverbs 3:35','Os sábios herdarão honra; porém os loucos terão sobre si confusão.'),
('Proverbs 4:1','Ouvi, filhos, a correção do pai; e prestai atenção, para que conheçais o entendimento.'),
('Proverbs 4:2','Pois eu vos dou boa doutrina; não deixeis a minha lei.'),
('Proverbs 4:3','Porque eu era filho do meu pai; tenro, e único perante a face de minha mãe.'),
('Proverbs 4:4','E ele me ensinava, e me dizia: Que teu coração retenha minhas palavras; guarda meus mandamentos, e vive.'),
('Proverbs 4:5','Adquire sabedoria, adquire entendimento; e não te esqueças nem te desvies das palavras de minha boca.'),
('Proverbs 4:6','Não a abandones, e ela te guardará; ama-a, e ela te conservará.'),
('Proverbs 4:7','O principal é a sabedoria; adquire sabedoria, e acima de tudo o que adquirires, adquire entendimento.'),
('Proverbs 4:8','Exalta-a, e ela te exaltará; quando tu a abraçares, ela te honrará.'),
('Proverbs 4:9','Ela dará a tua cabeça um ornamento gracioso; ela te entregará uma bela coroa.'),
('Proverbs 4:10','Ouve, filho meu, e recebe minhas palavras; e elas te acrescentarão anos de vida.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 4:11','Eu te ensino no caminho da sabedoria; e te faço andar pelos percursos direitos.'),
('Proverbs 4:12','Quando tu andares, teus passos não se estreitarão; e se tu correres, não tropeçarás.'),
('Proverbs 4:13','Toma a correção para si, e não a largues; guarda-a, porque ela é tua vida.'),
('Proverbs 4:14','Não entres pela vereda dos perversos, nem andes pelo caminho dos maus.'),
('Proverbs 4:15','Rejeita-o! Não passes por ele; desvia-te dele, e passa longe.'),
('Proverbs 4:16','Pois eles não dormem se não fizerem o mal; e ficam sem sono, se não fizerem tropeçar a alguém .'),
('Proverbs 4:17','Porque comem pão da maldade, e bebem vinho de violências.'),
('Proverbs 4:18','Mas o caminho dos justos é como a luz brilhante, que vai, e ilumina até o dia ficar claro por completo.'),
('Proverbs 4:19','O caminho dos perversos é como a escuridão; não sabem nem em que tropeçam.'),
('Proverbs 4:20','Filho meu, presta atenção às minhas palavras; e ouve as minhas instruções.'),
('Proverbs 4:21','Não as deixes ficarem longe de teus olhos; guarda-as no meio de teu coração.'),
('Proverbs 4:22','Porque são vida para aqueles que as encontram; e saúde para todo o seu corpo.'),
('Proverbs 4:23','Acima de tudo o que se deve guardar, guarda o teu coração; porque dele procedem as saídas da vida.'),
('Proverbs 4:24','Afasta de ti a perversidade da boca; e põe para longe de ti a corrupção dos lábios.'),
('Proverbs 4:25','Teus olhos olhem direito; tuas pálpebras estejam corretas diante de ti.'),
('Proverbs 4:26','Pondera o curso de teus pés; e todos os teus caminhos sejam bem ordenados.'),
('Proverbs 4:27','Não te desvies nem para a direita, nem para a esquerda; afasta teus pés do mal.'),
('Proverbs 5:1','Filho meu, presta atenção à minha sabedoria, inclina teus ouvidos ao meu entendimento.'),
('Proverbs 5:2','Para que guardes o bom-senso; e teus lábios conservem o conhecimento.'),
('Proverbs 5:3','Porque os lábios da mulher pervertida gotejam mel; e sua boca é mais suave que o azeite.'),
('Proverbs 5:4','Porém seu fim é mais amargo que o absinto; é afiado como a espada de dois fios.'),
('Proverbs 5:5','Os pés dela descem à morte; seus passos pegam o mundo dos mortos.'),
('Proverbs 5:6','Para que não ponderes a vereda da vida, os percursos delas são errantes, e tu não os conhecerás.'),
('Proverbs 5:7','E agora, filhos, escutai-me; e não vos desvieis das palavras de minha boca.'),
('Proverbs 5:8','Mantenha teu caminho longe dela; e não te aproximes da porta da casa dela.'),
('Proverbs 5:9','Para que não dês tua honra a outros, nem teus anos de vida aos cruéis.'),
('Proverbs 5:10','Para que estranhos não se fartem de teu poder, e teus trabalhos não sejam aproveitados em casa alheia;'),
('Proverbs 5:11','E gemas em teu fim, quando tua carne e teu corpo estiverem consumidos.'),
('Proverbs 5:12','E digas: Como eu odiei a correção, e meu coração desprezou a repreensão?'),
('Proverbs 5:13','E não escutei a voz de meus ensinadores, nem ouvi a meus mestres.'),
('Proverbs 5:14','Quase me achei em todo mal, no meio da congregação e do ajuntamento.'),
('Proverbs 5:15','Bebe água de tua própria cisterna, e das correntes de teu próprio poço.'),
('Proverbs 5:16','Derramar-se-iam por fora tuas fontes, e pelas ruas os ribeiros de águas?'),
('Proverbs 5:17','Sejam somente para ti, e não para os estranhos contigo.'),
('Proverbs 5:18','Seja bendito o teu manancial, e alegra-te com a mulher de tua juventude.'),
('Proverbs 5:19','Seja ela uma cerva amorosa e gazela graciosa; que os seios dela te fartem em todo tempo; e anda pelo caminho do amor dela continuamente.'),
('Proverbs 5:20','E por que tu, filho meu, andarias perdido pela estranha, e abraçarias o peito da mulher alheia?'),
('Proverbs 5:21','Pois os caminhos do homem estão perante os olhos do SENHOR; e ele pondera todos os seus percursos.'),
('Proverbs 5:22','O perverso será preso pelas suas próprias perversidades; e será detido pelas cordas de seu próprio pecado.'),
('Proverbs 5:23','Ele morrerá pela falta de correção; e andará sem rumo pela grandeza de sua loucura.'),
('Proverbs 6:1','Filho meu, se ficaste fiador por teu próximo, se deste tua garantia ao estranho;'),
('Proverbs 6:2','Se tu foste capturado pelas palavras de tua própria boca, e te prendeste pelas palavras de tua boca,'),
('Proverbs 6:3','Então faze isto agora, meu filho, e livra-te, pois caíste nas mãos de teu próximo; vai, humilha-te, e insiste exaustivamente ao teu próximo.'),
('Proverbs 6:4','Não dês sono aos teus olhos, nem cochilo às tuas pálpebras.'),
('Proverbs 6:5','Livra-te, como a corça do caçador, como o pássaro do caçador de aves.'),
('Proverbs 6:6','Vai até a formiga, preguiçoso; olha para os caminhos dela, e sê sábio.'),
('Proverbs 6:7','Ela, mesmo não tendo chefe, nem fiscal, nem dominador,'),
('Proverbs 6:8','Prepara seu alimento no verão, na ceifa ajunta seu mantimento.'),
('Proverbs 6:9','Ó preguiçoso, até quando estarás deitado? Quando te levantarás de teu sono?'),
('Proverbs 6:10','Um pouco de sono, um pouco de cochilo; um pouco de descanso com as mãos cruzadas;'),
('Proverbs 6:11','Assim a pobreza virá sobre ti como um assaltante; a necessidade chegará a ti como um homem armado.'),
('Proverbs 6:12','O homem mal, o homem injusto, anda com uma boca perversa.'),
('Proverbs 6:13','Ele acena com os olhos, fala com seus pés, aponta com seus dedos.'),
('Proverbs 6:14','Perversidades há em seu coração; todo o tempo ele trama o mal; anda semeando brigas.'),
('Proverbs 6:15','Por isso sua perdição virá repentinamente; subitamente ele será quebrado, e não haverá cura.'),
('Proverbs 6:16','Estas seis coisas o SENHOR odeia; e sete sua alma abomina:'),
('Proverbs 6:17','Olhos arrogantes, língua mentirosa, e mãos que derramam sangue inocente;'),
('Proverbs 6:18','O coração que trama planos malignos, pés que se apressam a correr para o mal;'),
('Proverbs 6:19','A falsa testemunha, que sopra mentiras; e o que semeia brigas entre irmãos.'),
('Proverbs 6:20','Filho meu, guarda o mandamento de teu pai; e não abandones a lei de tua mãe.'),
('Proverbs 6:21','Amarra-os continuamente em teu coração; e pendura-os ao teu pescoço.'),
('Proverbs 6:22','Quando caminhares, isto te guiará; quando deitares, isto te guardará; quando acordares, isto falará contigo.'),
('Proverbs 6:23','Porque o mandamento é uma lâmpada, e a lei é luz; e as repreensões para correção são o caminho da vida;'),
('Proverbs 6:24','Para te protegerem da mulher má, das lisonjas da língua da estranha.'),
('Proverbs 6:25','Não cobices a formosura dela em teu coração; nem te prenda em seus olhos.'),
('Proverbs 6:26','Porque pela mulher prostituta chega-se a pedir um pedaço de pão; e a mulher de outro homem anda à caça de uma alma preciosa.'),
('Proverbs 6:27','Por acaso pode alguém botar fogo em seu peito, sem que suas roupas se queimem?'),
('Proverbs 6:28','Ou alguém pode andar sobre as brasas, sem seus pés se arderem?'),
('Proverbs 6:29','Assim será aquele que se deitar com a mulher de seu próximo; não será considerado inocente todo aquele que a tocar.'),
('Proverbs 6:30','Não se despreza ao ladrão, quando furta para saciar sua alma, tendo fome;'),
('Proverbs 6:31','Mas, se for achado, ele pagará sete vezes mais; ele terá que dar todos os bens de sua casa.'),
('Proverbs 6:32','Porém aquele que adultera com mulher alheia tem falta de entendimento; quem faz isso destrói sua própria alma.'),
('Proverbs 6:33','Ele encontrará castigo e desgraça; e sua desonra nunca será apagada.'),
('Proverbs 6:34','Porque ciúmes são a fúria do marido, e ele de maneira nenhuma terá misericórdia no dia da vingança.'),
('Proverbs 6:35','Ele não aceitará nenhum pagamento pela culpa; nem consentirá, ainda que aumentes os presentes.'),
('Proverbs 7:1','Filho meu, guarda minhas palavras; e deposita em ti meus mandamentos.'),
('Proverbs 7:2','Guarda meus mandamentos, e vive; e minha lei, como as pupilas de teus olhos.'),
('Proverbs 7:3','Ata-os aos teus dedos; escreve-os na tábua do teu coração.'),
('Proverbs 7:4','Dize à sabedoria: Tu és minha irmã; E à prudência chama de parente.'),
('Proverbs 7:5','Para que te guardem da mulher alheia, da estranha, que lisonjeia com suas palavras.'),
('Proverbs 7:6','Porque da janela de minha casa, pelas minhas grades eu olhei;'),
('Proverbs 7:7','E vi entre os simples, prestei atenção entre os jovens, um rapaz que tinha falta de juízo;'),
('Proverbs 7:8','Que estava passando pela rua junto a sua esquina, e seguia o caminho da casa dela;'),
('Proverbs 7:9','No crepúsculo, ao entardecer do dia, no escurecer da noite e nas trevas.'),
('Proverbs 7:10','E eis que uma mulher lhe saiu ao encontro, com roupas de prostituta, e astuta de coração.'),
('Proverbs 7:11','Esta era barulhenta e insubordinada; os pés dela não paravam em sua casa.'),
('Proverbs 7:12','De tempos em tempos ela fica fora de casa ,nas ruas, espreitando em todos os cantos.'),
('Proverbs 7:13','Então ela o pegou, e o beijou; e com atrevimento em seu rosto, disse-lhe:'),
('Proverbs 7:14','Sacrifícios pacíficos tenho comigo; hoje paguei meus votos.'),
('Proverbs 7:15','Por isso saí para te encontrar; para buscar apressadamente a tua face, e te achei.'),
('Proverbs 7:16','Já preparei minha cama com cobertas; com tecidos de linho fino do Egito.'),
('Proverbs 7:17','Já perfumei meu leito com mirra, aloés e canela.'),
('Proverbs 7:18','Vem comigo ; iremos nos embebedar de paixões até a manhã, e nos alegraremos de amores.'),
('Proverbs 7:19','Porque meu marido não está em casa; ele viajou para longe.'),
('Proverbs 7:20','Ele tomou uma bolsa de dinheiro em sua mão; e só volta para casa no dia determinado.'),
('Proverbs 7:21','Ela o convenceu com suas muitas palavras sedutoras; com a lisonja de seus lábios ela o persuadiu.'),
('Proverbs 7:22','Ele foi logo após ela, como o boi vai ao matadouro; e como o louco ao castigo das prisões.'),
('Proverbs 7:23','Até que uma flecha atravesse seu fígado; como a ave que se apressa para a armadilha, e não sabe que está armada contra sua vida.'),
('Proverbs 7:24','Agora pois, filhos, escutai-me; e prestai atenção às palavras de minha boca.'),
('Proverbs 7:25','Que teu coração não se desvie para os caminhos dela, e não andes perdido pelas veredas dela.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 7:26','Porque ela derrubou a muitos feridos; e o total dos mortos por ela foram muitos.'),
('Proverbs 7:27','A casa dela são caminhos para o mundo dos mortos, que descem para as câmaras da morte.'),
('Proverbs 8:1','Por acaso a sabedoria não clama, e a inteligência não solta sua voz?'),
('Proverbs 8:2','Nos lugares mais altos, junto ao caminho, nas encruzilhadas das veredas, ela se põe.'),
('Proverbs 8:3','Ao lado das portas, à entrada da cidade; na entrada dos portões, ela grita:'),
('Proverbs 8:4','Varões, eu vos clamo; dirijo minha voz aos filhos dos homens.'),
('Proverbs 8:5','Vós que sois ingênuos, entendei a prudência; e vós que sois loucos, entendei de coração.'),
('Proverbs 8:6','Ouvi, porque falarei coisas nobres; e abro meus lábios para a justiça.'),
('Proverbs 8:7','Porque minha boca declarará a verdade; e meus lábios abominam a maldade.'),
('Proverbs 8:8','Todas as coisas que digo com minha boca são justas; não há nelas coisa alguma que seja distorcida ou perversa.'),
('Proverbs 8:9','Todas elas são corretas para aquele que as entende; e justas para os que encontram conhecimento.'),
('Proverbs 8:10','Aceitai minha correção, e não prata; e o conhecimento mais que o ouro fino escolhido.'),
('Proverbs 8:11','Porque a sabedoria é melhor do que rubis; e todas as coisas desejáveis nem sequer podem ser comparadas a ela.'),
('Proverbs 8:12','Eu, a Sabedoria, moro com a Prudência; e tenho o conhecimento do conselho.'),
('Proverbs 8:13','O temor ao SENHOR é odiar o mal: a soberba e a arrogância, o mal caminho e a boca perversa, eu os odeio.'),
('Proverbs 8:14','A mim pertence o conselho e a verdadeira sabedoria; eu tenho prudência e poder.'),
('Proverbs 8:15','Por meio de mim os reis governam, e os príncipes decretam justiça.'),
('Proverbs 8:16','Por meio de mim os governantes dominam; e autoridades, todos os juízes justos.'),
('Proverbs 8:17','Eu amo os que me amam; e os que me buscam intensamente me acharão.'),
('Proverbs 8:18','Bens e honra estão comigo; assim como a riqueza duradoura e a justiça.'),
('Proverbs 8:19','Meu fruto é melhor que o ouro, melhor que o ouro refinado; e meus produtos melhores que a prata escolhida.'),
('Proverbs 8:20','Eu faço andar pelo caminho da justiça, no meio das veredas do juízo;'),
('Proverbs 8:21','Para eu dar herança aos que me amam, e encher seus tesouros.'),
('Proverbs 8:22','O SENHOR me adquiriu no princípio de seu caminho; desde antes de suas obras antigas.'),
('Proverbs 8:23','Desde a eternidade eu fui ungida; desde o princípio; desde antes do surgimento da terra.'),
('Proverbs 8:24','Quando ainda não havia abismos, eu fui gerada; quando ainda não havia fontes providas de muitas águas.'),
('Proverbs 8:25','Antes que os montes fossem firmados; antes dos morros, eu fui gerada.'),
('Proverbs 8:26','Quando ele ainda não tinha feito a terra, nem os campos; nem o princípio da poeira do mundo.'),
('Proverbs 8:27','Quando preparava os céus, ali eu estava; quando ele desenhava ao redor da face do abismo.'),
('Proverbs 8:28','Quando firmava as nuvens de cima, quando fortificava as fontes do abismo.'),
('Proverbs 8:29','Quando colocava ao mar o seu limite, para que as águas não ultrapassassem seu mandado; quando estabelecia os fundamentos da terra.'),
('Proverbs 8:30','Então eu estava com ele como um pupilo; e eu era seu agrado a cada dia, alegrando perante ele em todo tempo.'),
('Proverbs 8:31','Alegrando na habitação de sua terra; e concedendo meus agrados aos filhos dos homens.'),
('Proverbs 8:32','Portanto agora, filhos, ouvi-me; porque bem-aventurados serão os que guardarem meus caminhos.'),
('Proverbs 8:33','Ouvi a correção, e sede sábios; e não a rejeiteis.'),
('Proverbs 8:34','Bem-aventurado é o homem que me ouve; que vigia em minhas portas diariamente, que guarda as ombreiras de minhas entradas.'),
('Proverbs 8:35','Porque aquele que me encontrar, encontrará a vida; e obterá o favor do SENHOR.'),
('Proverbs 8:36','Mas aquele que pecar contra mim fará violência à sua própria alma; todos os que me odeiam amam a morte.'),
('Proverbs 9:1','A verdadeira sabedoria edificou sua casa; ela lavrou suas sete colunas.'),
('Proverbs 9:2','Ela sacrificou seu sacrifício, misturou seu vinho, e preparou sua mesa.'),
('Proverbs 9:3','Mandou suas servas, e está convidando desde os pontos mais altos da cidade, dizendo:'),
('Proverbs 9:4','Qualquer um que for ingênuo, venha aqui.Aos que têm falta de entendimento, ela diz:'),
('Proverbs 9:5','Vinde, comei do meu pão; e bebei do vinho que misturei.'),
('Proverbs 9:6','Abandonai a tolice; e vivei; e andai pelo caminho da prudência.'),
('Proverbs 9:7','Aquele que repreende ao zombador, toma desonra para si mesmo; e o que tenta corrigir ao perverso acaba sendo manchado.'),
('Proverbs 9:8','Não repreendas ao zombador, para que ele não te odeie; repreende ao sábio, e ele te amará.'),
('Proverbs 9:9','Ensina ao sábio, e ele será mais sábio ainda; instrui ao justo, e ele aumentará seu conhecimento.'),
('Proverbs 9:10','O temor ao SENHOR é o princípio da sabedoria; e o conhecimento dos santos é a prudência.'),
('Proverbs 9:11','Porque por mim teus dias serão multiplicados; e anos de vida a ti serão aumentados.'),
('Proverbs 9:12','Se fores sábio, serás sábio para ti; e se fores zombador, somente tu aguentarás.'),
('Proverbs 9:13','A mulher louca é causadora de tumultos; ela é tola, e não sabe coisa alguma.'),
('Proverbs 9:14','E se senta à porta de sua casa, sobre uma cadeira, nos lugares altos da cidade;'),
('Proverbs 9:15','Para chamar aos que passam pelo caminho, e passam por suas veredas, dizendo :'),
('Proverbs 9:16','Qualquer um que for ingênuo, venha aqui! E aos que tem falta de entendimento, ela diz:'),
('Proverbs 9:17','As águas roubadas são doces; e o pão escondido é agradável.'),
('Proverbs 9:18','Porém aquele que a ouve não sabe que ali estão os mortos; os convidados dela estão nas profundezas do mundo dos mortos.'),
('Proverbs 10:1','Provérbios de Salomão:O filho sábio alegra ao pai; mas o filho tolo é tristeza para sua mãe.'),
('Proverbs 10:2','Tesouros da perversidade para nada aproveitam; porém a justiça livra da morte.'),
('Proverbs 10:3','O SENHOR não permite a alma do justo passar fome, porém arruína o interesse dos perversos.'),
('Proverbs 10:4','Aquele que trabalha com mão preguiçosa empobrece; mas a mão de quem trabalha com empenho enriquece.'),
('Proverbs 10:5','Aquele que ajunta no verão é filho prudente; mas o que dorme na ceifa é filho causador de vergonha.'),
('Proverbs 10:6','Há bênçãos sobre a cabeça dos justos; mas a violência cobre a boca dos perversos.'),
('Proverbs 10:7','A lembrança do justo será uma bênção; mas o nome dos perversos apodrecerá.'),
('Proverbs 10:8','O sábio de coração aceita os mandamentos; mas o louco de lábios será derrubado.'),
('Proverbs 10:9','Aquele que anda em sinceridade anda seguro; mas o que perverte seus caminhos será conhecido.'),
('Proverbs 10:10','Aquele que pisca os olhos maliciosamente gera dores; e o louco de lábios será derrubado.'),
('Proverbs 10:11','A boca do justo é um manancial de vida; mas a boca dos perversos está coberta de violência.'),
('Proverbs 10:12','O ódio desperta brigas; mas o amor cobre todas as transgressões.'),
('Proverbs 10:13','Nos lábios do bom entendedor se acha sabedoria, mas uma vara está às costas daquele que não tem entendimento.'),
('Proverbs 10:14','Os sábios guardam consigo sabedoria; mas a boca do tolo está perto da perturbação.'),
('Proverbs 10:15','A prosperidade do rico é a sua cidade fortificada; a pobreza dos necessitados é sua perturbação.'),
('Proverbs 10:16','A obra do justo é para a vida; os frutos do perverso, para o pecado.'),
('Proverbs 10:17','O caminho para a vida é d aquele que guarda a correção; mas aquele que abandona a repreensão anda sem rumo.'),
('Proverbs 10:18','Aquele que esconde o ódio tem lábios mentirosos; e o que produz má fama é tolo.'),
('Proverbs 10:19','Na abundância de palavras não há falta de transgressão; mas aquele que refreia seus lábios é prudente.'),
('Proverbs 10:20','A língua do justo é como prata escolhida; o coração dos perversos vale pouco.'),
('Proverbs 10:21','Os lábios dos justo apascentam a muitos; mas os tolos, por falta de entendimento, morrem.'),
('Proverbs 10:22','É a bênção do SENHOR que enriquece; e ele não lhe acrescenta dores.'),
('Proverbs 10:23','Para o tolo, fazer o mal é uma diversão; mas para o homem bom entendedor, divertida é a sabedoria.'),
('Proverbs 10:24','O temor do perverso virá sobre ele, mas o desejo dos justos será concedido.'),
('Proverbs 10:25','Assim como o vento passa, assim também o perverso não mais existirá; mas o justo tem um alicerce eterno.'),
('Proverbs 10:26','Assim como vinagre para os dentes, e como fumaça para os olhos, assim também é o preguiçoso para aqueles que o mandam.'),
('Proverbs 10:27','O temor ao SENHOR faz aumentar os dias; mas os anos dos perversos serão encurtados.'),
('Proverbs 10:28','A esperança dos justos é alegria; mas a expectativa dos perversos perecerá.'),
('Proverbs 10:29','O caminho do SENHOR é fortaleza para os corretos, mas ruína para os que praticam maldade.'),
('Proverbs 10:30','O justo nunca será removido, mas os perversos não habitarão a terra.'),
('Proverbs 10:31','A boca do justo produz sabedoria, mas a língua perversa será cortada fora.'),
('Proverbs 10:32','Os lábios do justo sabem o que é agradável; mas a boca dos perversos é cheia de perversidades.'),
('Proverbs 11:1','A balança enganosa é abominação ao SENHOR; mas o peso justo é seu prazer.'),
('Proverbs 11:2','Quando vem a arrogância, vem também a desonra; mas com os humildes está a sabedoria.'),
('Proverbs 11:3','A integridade dos corretos os guia; mas a perversidade dos enganadores os destruirá.'),
('Proverbs 11:4','Nenhum proveito terá a riqueza no dia da ira; mas a justiça livrará da morte.'),
('Proverbs 11:5','A justiça do íntegro endireitará seu caminho; mas o perverso cairá por sua perversidade.'),
('Proverbs 11:6','A justiça dos corretos os livrará; mas os transgressores serão presos em sua própria perversidade.'),
('Proverbs 11:7','Quando o homem mau morre, sua expectativa morre; e a esperança de seu poder perece.'),
('Proverbs 11:8','O justo é livrado da angústia; e o perverso vem em seu lugar.'),
('Proverbs 11:9','O hipócrita com a boca prejudica ao seu próximo; mas os justos por meio do conhecimento são livrados.'),
('Proverbs 11:10','No bem dos justos, a cidade se alegra muito; e quando os perversos perecem, há alegria.'),
('Proverbs 11:11','Pelo bênção dos sinceros a cidade se exalta; mas pela boca dos perversos ela se destrói.'),
('Proverbs 11:12','Aquele que não tem entendimento despreza a seu próximo; mas o homem bom entendedor se mantêm calado.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 11:13','Aquele que conta fofocas revela o segredo; mas o fiel de espírito encobre o assunto.'),
('Proverbs 11:14','Quando não há conselhos sábios, o povo cai; mas na abundância de bons conselheiros consiste o livramento.'),
('Proverbs 11:15','Certamente aquele que se tornar fiador de algum estranho passará por sofrimento; mas aquele odeia firmar compromissos ficará seguro.'),
('Proverbs 11:16','A mulher graciosa guarda a honra, assim como os violentos guardam as riquezas.'),
('Proverbs 11:17','O homem bondoso faz bem à sua alma; mas o cruel atormenta sua própria carne.'),
('Proverbs 11:18','O perverso recebe falso pagamento; mas aquele que semeia justiça terá uma recompensa fiel.'),
('Proverbs 11:19','Assim como a justiça leva para a vida; assim também aquele que segue o mal é levado para sua própria morte.'),
('Proverbs 11:20','O SENHOR abomina os perversos de coração; porém ele se agrada que caminham com sinceridade.'),
('Proverbs 11:21','Com certeza o mal não será absolvido; mas a semente dos justos escapará livre.'),
('Proverbs 11:22','A mulher bela mas sem discrição é como uma joia no focinho de uma porca.'),
('Proverbs 11:23','O desejo dos justos é somente para o bem; mas a esperança dos perversos é a fúria.'),
('Proverbs 11:24','Há quem dá generosamente e tem cada vez mais; e há quem retém mais do que é justo e empobrece.'),
('Proverbs 11:25','A alma generosa prosperará, e aquele que saciar  também será saciado.'),
('Proverbs 11:26','O povo amaldiçoa ao que retém o trigo; mas bênção haverá sobre a cabeça daquele que o vende.'),
('Proverbs 11:27','Aquele que com empenho busca o bem, busca favor; porém o que procura o mal, sobre ele isso lhe virá.'),
('Proverbs 11:28','Aquele que confia em suas riquezas cairá; mas os justos florescerão como as folhas.'),
('Proverbs 11:29','Aquele que perturba sua própria casa herdará vento; e o tolo será servo do sábio de coração.'),
('Proverbs 11:30','O fruto do justo é uma árvore de vida; e o que ganha almas é sábio.'),
('Proverbs 11:31','Ora, se o justo recebe seu pagamento na terra, quanto mais o perverso e o pecador!'),
('Proverbs 12:1','Aquele que ama a correção ama o conhecimento; mas aquele que odeia a repreensão é um bruto.'),
('Proverbs 12:2','O homem de bem ganha o favor do SENHOR; mas ao homem de pensamentos perversos, ele o condenará.'),
('Proverbs 12:3','O homem não prevalecerá pela perversidade; mas a raiz dos justos não será removida.'),
('Proverbs 12:4','A mulher virtuosa é a coroa de seu marido; mas a causadora de vergonha é como uma podridão em seus ossos.'),
('Proverbs 12:5','Os pensamentos dos justos são de bom juízo; mas os conselhos dos perversos são enganosos.'),
('Proverbs 12:6','As palavras dos perversos são para espreitar o derramamento de sangue de inocentes ; mas a boca dos corretos os livrará.'),
('Proverbs 12:7','Os perversos serão transtornados, e não existirão mais ; porém a casa dos justos permanecerá.'),
('Proverbs 12:8','Cada um será elogiado conforme seu entendimento; mas o perverso de coração será desprezado.'),
('Proverbs 12:9','Melhor é o que estima pouco a si mesmo mas tem quem o sirva, do que aquele que elogia e si mesmo, mas nem sequer tem pão.'),
('Proverbs 12:10','O justo dá atenção à vida de seus animais; mas até as misericórdias dos perversos são cruéis.'),
('Proverbs 12:11','Aquele que lavra sua terra se saciará de pão; mas o que segue coisas inúteis tem falta de juízo.'),
('Proverbs 12:12','O perverso deseja armadilhas malignas; porém a raiz dos justos produzirá seu fruto .'),
('Proverbs 12:13','O perverso é capturado pela transgressão de seus lábios, mas o justo sairá da angústia.'),
('Proverbs 12:14','Cada um se sacia do bem pelo fruto de sua própria boca; e a recompensa das mãos do homem lhe será entregue de volta.'),
('Proverbs 12:15','O caminho do tolo é correto aos seus próprios olhos; mas aquele que ouve o bom conselho é sábio.'),
('Proverbs 12:16','A ira do tolo é conhecida no mesmo dia, mas o prudente ignora o insulto.'),
('Proverbs 12:17','Aquele que fala a verdade conta a justiça; porém a testemunha falsa conta o engano.'),
('Proverbs 12:18','Há alguns que falam palavras como que golpes de espada; porém a língua do sábios é como um remédio.'),
('Proverbs 12:19','O lábio da verdade ficará para sempre, mas a língua da falsidade dura por apenas um momento.'),
('Proverbs 12:20','Há engano no coração dos que tramam o mal; mas os que aconselham a paz têm alegria.'),
('Proverbs 12:21','Nenhuma adversidade sobrevirá ao justos; mas os perversos se encherão de mal.'),
('Proverbs 12:22','Os lábios mentirosos são abomináveis ao SENHOR, mas dos que falam a verdade são seu prazer.'),
('Proverbs 12:23','O homem prudente é discreto em conhecimento; mas o coração dos tolos proclama a loucura.'),
('Proverbs 12:24','A mão dos que trabalham com empenho dominará, e os preguiçosos se tornarão escravos.'),
('Proverbs 12:25','A ansiedade no coração do homem o abate; mas uma boa palavra o alegra.'),
('Proverbs 12:26','O justo age cuidadosamente para com seu próximo, mas o caminho dos perversos os faz errar.'),
('Proverbs 12:27','O preguiçoso não assa aquilo que caçou, mas a riqueza de quem trabalha com empenho lhe é preciosa.'),
('Proverbs 12:28','Na vereda da justiça está a vida; e no caminho de seu percurso não há morte.'),
('Proverbs 13:1','O filho sábio ouve a correção do pai; mas o zombador não escuta a repreensão.'),
('Proverbs 13:2','Cada um comerá do bem pelo fruto de sua boca, mas a alma dos infiéis deseja a violência.'),
('Proverbs 13:3','Quem toma cuidado com sua boca preserva sua alma; mas aquele que abre muito seus lábios será arruinado.'),
('Proverbs 13:4','A alma do preguiçoso deseja, mas nada consegue ; porém a alma dos trabalham com empenho prosperará.'),
('Proverbs 13:5','O justo odeia a palavra mentirosa, mas o perverso age de forma repugnante e vergonhosa.'),
('Proverbs 13:6','A justiça guarda aquele que tem um caminho íntegro; mas a perversidade transtornará ao pecador.'),
('Proverbs 13:7','Há alguns que fingem ser ricos, mesmo nada tendo; e outros que fingem ser pobres, mesmo tendo muitos bens.'),
('Proverbs 13:8','O resgate da vida de cada um são suas riquezas; mas o pobre não ouve ameaças.'),
('Proverbs 13:9','A luz dos justos se alegra, mas a lâmpada dos perversos se apagará.'),
('Proverbs 13:10','A arrogância só produz brigas; mas com os que aceitam conselhos está a sabedoria.'),
('Proverbs 13:11','A riqueza ganha sem esforço será perdida; mas aquele que a obtém pelas próprias mãos terá cada vez mais.'),
('Proverbs 13:12','A esperança que demora enfraquece o coração, mas o desejo cumprido é como uma árvore de vida.'),
('Proverbs 13:13','Quem despreza a boa palavra perecerá; mas aquele que teme ao mandamento será recompensado.'),
('Proverbs 13:14','A doutrina do sábio é manancial de vida, para se desviar das ciladas da morte.'),
('Proverbs 13:15','O bom entendimento alcança o favor, mas o caminho dos infiéis é áspero.'),
('Proverbs 13:16','Todo prudente age com conhecimento, mas o tolo espalha sua loucura.'),
('Proverbs 13:17','O mensageiro perverso cai no mal, mas o representante fiel é como um remédio.'),
('Proverbs 13:18','Haverá pobreza e vergonha ao que rejeita a correção; mas aquele que atende à repreensão será honrado.'),
('Proverbs 13:19','O desejo realizado agrada a alma, mas os tolos abominam se afastar do mal.'),
('Proverbs 13:20','Quem anda com os sábios se torna sábio; mas aquele que acompanha os tolos sofrerá.'),
('Proverbs 13:21','O mal perseguirá os pecadores, mas os justos serão recompensados com o bem.'),
('Proverbs 13:22','O homem de bem deixará herança aos filhos de seus filhos; mas a riqueza do pecador está reservada para o justo.'),
('Proverbs 13:23','A lavoura dos pobres gera muita comida; mas há alguns que se destroem por falta de juízo.'),
('Proverbs 13:24','Aquele que retém sua vara odeia a seu filho; porém aquele que o ama, desde cedo o castiga.'),
('Proverbs 13:25','O justo come até sua alma estar saciada; mas o ventre dos perversos passará por necessidade.'),
('Proverbs 14:1','Toda mulher sábia edifica sua casa; porém a tola a derruba com suas mãos.'),
('Proverbs 14:2','Aquele que anda corretamente teme ao SENHOR; mas o que se desvia de seus caminhos o despreza.'),
('Proverbs 14:3','Na boca do tolo está a vara da arrogância, porém os lábios dos sábios os protegem.'),
('Proverbs 14:4','Não havendo bois, o celeiro fica limpo; mas pela força do boi há uma colheita abundante.'),
('Proverbs 14:5','A testemunha verdadeira não mentirá, mas a testemunha falsa declara mentiras.'),
('Proverbs 14:6','O zombador busca sabedoria, mas não acha nenhuma; mas o conhecimento é fácil para o prudente.'),
('Proverbs 14:7','Afasta-te do homem tolo, porque nele não encontrarás lábios inteligentes.'),
('Proverbs 14:8','A sabedoria do prudente é entender seu caminho; mas a loucura dos tolos é engano.'),
('Proverbs 14:9','Os tolos zombam da culpa, mas entre os corretos está o favor.'),
('Proverbs 14:10','O coração conhece sua própria amargura, e o estranho não pode partilhar sua alegria.'),
('Proverbs 14:11','A casa dos perversos será destruída, mas a tenda dos corretos florescerá.'),
('Proverbs 14:12','Há um caminho que parece correto para o homem, porém o fim dele são caminhos de morte.'),
('Proverbs 14:13','Até no riso o coração terá dor, e o fim da alegria é a tristeza.'),
('Proverbs 14:14','Quem se desvia de coração será cheio de seus próprios caminhos, porém o homem de bem será recompensado pelos seus.'),
('Proverbs 14:15','O ingênuo crê em toda palavra, mas o prudente pensa cuidadosamente sobre seus passos.'),
('Proverbs 14:16','O sábio teme, e se afasta do mal; porém o tolo se precipita e se acha seguro.'),
('Proverbs 14:17','Quem se ira rapidamente faz loucuras, e o homem de maus pensamentos será odiado.'),
('Proverbs 14:18','Os ingênuos herdarão a tolice, mas os prudentes serão coroados com o conhecimento.'),
('Proverbs 14:19','Os maus se inclinarão perante a face dos bons, e os perversos diante das portas do justo.'),
('Proverbs 14:20','O pobre é odiado até pelo seu próximo, porém os amigos dos ricos são muitos.'),
('Proverbs 14:21','Quem despreza a seu próximo, peca; mas aquele que demonstra misericórdia aos humildes é bem-aventurado.'),
('Proverbs 14:22','Por acaso não andam errados os que tramam o mal? Mas há bondade e fidelidade para os que planejam o bem.'),
('Proverbs 14:23','Em todo trabalho cansativo há proveito, mas o falar dos lábios só leva à pobreza.'),
('Proverbs 14:24','A coroa dos sábios é a sua riqueza; a loucura dos tolos é loucura.'),
('Proverbs 14:25','A testemunha verdadeira livra almas, mas aquele que declara mentiras é enganador.'),
('Proverbs 14:26','No temor ao SENHOR há forte confiança; e será refúgio para seus filhos.'),
('Proverbs 14:27','O temor ao SENHOR é manancial de vida, para se desviar dos laços da morte.'),
('Proverbs 14:28','Na multidão do povo está a honra do rei, mas a falta de gente é a ruína do príncipe.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 14:29','Quem demora para se irar tem muito entendimento, mas aquele de espírito impetuoso exalta a loucura.'),
('Proverbs 14:30','O coração em paz é vida para o corpo, mas a inveja é como podridão nos ossos.'),
('Proverbs 14:31','Quem oprime ao pobre insulta ao seu Criador; mas aquele que mostra compaixão ao necessitado o honra.'),
('Proverbs 14:32','Por sua malícia, o perverso é excluído; porém o justo até em sua morte mantém a confiança.'),
('Proverbs 14:33','No coração do prudente repousa a sabedoria; mas ela será conhecida até entre os tolos.'),
('Proverbs 14:34','A justiça exalta a nação, mas o pecado é a desgraça dos povos.'),
('Proverbs 14:35','O rei se agrada do seu servo prudente; porém ele mostrará seu furor ao causador de vergonha.'),
('Proverbs 15:1','A resposta suave desvia o furor, mas a palavra pesada faz a ira aumentar.'),
('Proverbs 15:2','A língua dos sábios faz bom uso da sabedoria, mas a boca dos tolos derrama loucura.'),
('Proverbs 15:3','Os olhos do SENHOR estão em todo lugar, observando os maus e os bons.'),
('Proverbs 15:4','Uma língua sã é árvore de vida; mas a perversidade nela é faz o espírito em pedaços.'),
('Proverbs 15:5','O tolo despreza a correção de seu pai; mas aquele que presta atenção à repreensão age com prudência.'),
('Proverbs 15:6','Na casa dos justo há um grande tesouro; mas na renda do perverso há perturbação.'),
('Proverbs 15:7','Os lábios dos sábios derramam conhecimento; mas o coração dos tolos não age assim.'),
('Proverbs 15:8','O sacrifício dos perversos é abominável ao SENHOR, mas a oração dos justos é seu agrado.'),
('Proverbs 15:9','Abominável ao SENHOR é o caminho do perverso; porém ele ama ao que segue a justiça.'),
('Proverbs 15:10','A correção é ruim para aquele que deixa o caminho; e quem odeia a repreensão morrerá.'),
('Proverbs 15:11','O mundo dos mortos e a perdição estão perante o SENHOR; quanto mais os corações dos filhos dos homens.'),
('Proverbs 15:12','O zombador não ama aquele que o repreende, nem se chegará aos sábios.'),
('Proverbs 15:13','O coração alegre anima o rosto, mas pela dor do coração o espírito se abate.'),
('Proverbs 15:14','O coração prudente buscará o conhecimento, mas a boca dos tolos se alimentará de loucura.'),
('Proverbs 15:15','Todos os dias do oprimido são maus, mas o coração alegre é como um banquete contínuo.'),
('Proverbs 15:16','Melhor é o pouco tendo o temor ao SENHOR, do que um grande tesouro tendo em si inquietação.'),
('Proverbs 15:17','Melhor é a comida de hortaliças tendo amor, do que a de boi cevado tendo em si ódio.'),
('Proverbs 15:18','O homem que fica irritado facilmente gera brigas; mas aquele que demora para se irar apaziguará o confronto.'),
('Proverbs 15:19','O caminho do preguiçoso é como uma cerca de espinhos; mas a vereda dos corretos é bem aplanada.'),
('Proverbs 15:20','O filho sábio alegra ao pai, mas o homem tolo despreza a sua mãe.'),
('Proverbs 15:21','A loucura é alegria para aquele que tem falta de prudência; mas o homem de bom entendimento andará corretamente.'),
('Proverbs 15:22','Os planos fracassam quando não há bom conselho; mas com abundância de conselheiros eles se confirmam.'),
('Proverbs 15:23','O homem se alegra com a resposta de sua boca; e como é boa a palavra a seu devido tempo!'),
('Proverbs 15:24','O caminho da vida leva o prudente para cima, para que se desvie do mundo dos mortos, que está abaixo.'),
('Proverbs 15:25','O SENHOR destruirá a casa dos arrogantes, mas confirmará os limites do terreno da viúva.'),
('Proverbs 15:26','Os pensamentos do mau são abomináveis ao SENHOR, mas ele se agrada das palavras dos puros.'),
('Proverbs 15:27','Quem pratica a ganância perturba sua própria casa; mas quem odeia subornos viverá.'),
('Proverbs 15:28','O coração do justo pensa bem naquilo que vai responder, mas a boca dos perversos derrama maldades em abundância.'),
('Proverbs 15:29','Longe está o SENHOR dos perversos, mas ele escuta a oração dos justos.'),
('Proverbs 15:30','A luz dos olhos alegra o coração; a boa notícia fortalece os ossos.'),
('Proverbs 15:31','Os ouvidos que escutam a repreensão da vida habitarão entre os sábios.'),
('Proverbs 15:32','Quem rejeita correção menospreza sua própria alma; mas aquele que escuta a repreensão adquire entendimento.'),
('Proverbs 15:33','O temor ao SENHOR corrige sabiamente; e antes da honra vem a humildade.'),
('Proverbs 16:1','Do homem são os planejamentos do coração, mas a reposta da boca vem do SENHOR.'),
('Proverbs 16:2','Todos os caminhos do homem são puros aos seus próprios olhos; mas o SENHOR pesa os espíritos.'),
('Proverbs 16:3','Confia tuas obras ao SENHOR, e teus pensamentos serão firmados.'),
('Proverbs 16:4','O SENHOR fez tudo para seu propósito; e até ao perverso para o dia do mal.'),
('Proverbs 16:5','O SENHOR abomina todo orgulhoso de coração; certamente não ficará impune.'),
('Proverbs 16:6','Com misericórdia e fidelidade a perversidade é reconciliada; e com o temor ao SENHOR se desvia do mal.'),
('Proverbs 16:7','Quando os caminhos do homem são agradáveis ao SENHOR, ele faz até seus inimigos terem paz com ele.'),
('Proverbs 16:8','Melhor é o pouco com justiça, do que a abundância de rendas com injustiça.'),
('Proverbs 16:9','O coração do homem planeja seu caminho, mas é o SENHOR que dirige seus passos.'),
('Proverbs 16:10','Nos lábios do rei estão palavras sublimes; sua boca não transgride quando julga.'),
('Proverbs 16:11','O peso e a balança justos pertencem ao SENHOR; a ele pertencem todos os pesos da bolsa.'),
('Proverbs 16:12','Os reis abominam fazer perversidade, porque com justiça é que se confirma o trono.'),
('Proverbs 16:13','Os lábios justos são do agrado dos reis, e eles amam ao que fala palavras direitas.'),
('Proverbs 16:14','A ira do rei é como mensageiros de morte; mas o homem sábio a apaziguará.'),
('Proverbs 16:15','No brilho do rosto do rei há vida; e seu favor é como uma nuvem de chuva tardia.'),
('Proverbs 16:16','Obter sabedoria é tão melhor do que o ouro! E obter sabedoria é mais excelente do que a prata.'),
('Proverbs 16:17','A estrada dos corretos se afasta do mal; e guarda sua alma quem vigia seu caminho.'),
('Proverbs 16:18','Antes da destruição vem a arrogância, e antes da queda vem a soberba de espírito.'),
('Proverbs 16:19','É melhor ser humilde de espírito com os mansos, do que repartir despojos com os arrogantes.'),
('Proverbs 16:20','Aquele que pensa prudentemente na palavra encontrará o bem; e quem confia no SENHOR é bem-aventurado.'),
('Proverbs 16:21','O sábio de coração será chamado de prudente; e a doçura dos lábios aumentará a instrução.'),
('Proverbs 16:22','Manancial de vida é o entendimento, para queles que o possuem; mas a instrução dos tolos é loucura.'),
('Proverbs 16:23','O coração do sábio dá prudência à sua boca; e sobre seus lábios aumentará a instrução.'),
('Proverbs 16:24','Favo de mel são as palavras suaves: doces para a alma, e remédio para os ossos.'),
('Proverbs 16:25','Há um caminho que parece direito ao homem, porém seu fim são caminhos de morte.'),
('Proverbs 16:26','A alma do trabalhador faz ele trabalhar para si, porque sua boca o obriga.'),
('Proverbs 16:27','O homem maligno cava o mal, e em seus lábios há como que um fogo ardente.'),
('Proverbs 16:28','O homem perverso levanta contenda, e o difamador faz até grandes amigos se separarem.'),
('Proverbs 16:29','O homem violento ilude a seu próximo, e o guia por um caminho que não é bom.'),
('Proverbs 16:30','Ele fecha seus olhos para imaginar perversidades; ele aperta os lábios para praticar o mal.'),
('Proverbs 16:31','Cabelos grisalhos são uma coroa de honra, caso se encontrem no caminho de justiça.'),
('Proverbs 16:32','Melhor é o que demora para se irritar do que o valente; e melhor é aquele que domina seu espírito do que aquele que toma uma cidade.'),
('Proverbs 16:33','A sorte é lançada no colo, mas toda decisão pertence ao SENHOR.'),
('Proverbs 17:1','Melhor é um pedaço seco de comida com tranquilidade, do que uma casa cheia de carne com briga.'),
('Proverbs 17:2','O servo prudente dominará o filho causador de vergonha, e receberá parte da herança entre os irmãos.'),
('Proverbs 17:3','O crisol é para a prata, e o forno para o ouro; mas o SENHOR prova os corações.'),
('Proverbs 17:4','O malfeitor presta atenção ao lábio injusto; o mentiroso inclina os ouvidos à língua maligna.'),
('Proverbs 17:5','Quem ridiculariza o pobre insulta o seu Criador; aquele que se alegra da calamidade não ficará impune.'),
('Proverbs 17:6','A coroa dos idosos são os filhos de seus filhos; e a glória dos filhos são seus pais.'),
('Proverbs 17:7','Não é adequado ao tolo falar com elegância; muito menos para o príncipe falar mentiras.'),
('Proverbs 17:8','O presente é como uma pedra preciosa aos olhos de seus donos; para onde quer que se voltar, tentará ter algum proveito.'),
('Proverbs 17:9','Quem perdoa a transgressão busca a amizade; mas quem repete o assunto afasta amigos íntimos.'),
('Proverbs 17:10','A repreensão entra mais profundamente no prudente do que cem açoites no tolo.'),
('Proverbs 17:11','Na verdade quem é mal busca somente a rebeldia; mas o mensageiro cruel será enviado contra ele.'),
('Proverbs 17:12','É melhor ao homem encontrar uma ursa roubada de seus filhotes ,do que um tolo em sua loucura.'),
('Proverbs 17:13','Quanto ao que devolve o mal no lugar do bem, o mal nunca se afastará de sua casa.'),
('Proverbs 17:14','Começar uma briga é como deixar águas rolarem; por isso, abandona a discussão antes que haja irritação.'),
('Proverbs 17:15','Quem absolve ao perverso e quem condena ao justo, ambos são abomináveis ao SENHOR.'),
('Proverbs 17:16','Para que serve o dinheiro na mão do tolo, já que ele não tem interesse em obter sabedoria?'),
('Proverbs 17:17','O amigo ama em todo tempo, e o irmão nasce para ajudar na angústia.'),
('Proverbs 17:18','O homem imprudente assume compromisso, ficando como fiador de seu próximo.'),
('Proverbs 17:19','Quem ama a briga, ama a transgressão; quem constrói alta sua porta busca ruína.'),
('Proverbs 17:20','O perverso de coração nunca encontrará o bem; e quem distorce as palavras de sua língua cairá no mal.'),
('Proverbs 17:21','Quem gera o louco cria sua própria tristeza; e o pai do imprudente não se alegrará.'),
('Proverbs 17:22','O coração alegre é um bom remédio, mas o espírito abatido faz os ossos se secarem.'),
('Proverbs 17:23','O perverso toma o presente do seio, para perverter os caminhos da justiça.'),
('Proverbs 17:24','A sabedoria está diante do rosto do prudente; porém os olhos do tolo estão voltados para os confins da terra.'),
('Proverbs 17:25','O filho tolo é tristeza para seu pai, e amargura para aquela que o gerou.'),
('Proverbs 17:26','Também não é bom punir ao justo, nem bater nos príncipes por causa da justiça.'),
('Proverbs 17:27','Quem entende o conhecimento guarda suas palavras; e o homem de bom entendimento é de espírito calmo.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 17:28','Até o tolo, quando está calado, é considerado como sábio; e quem fecha seus lábios, como de bom senso.'),
('Proverbs 18:1','Quem se isola busca seu próprio desejo; ele se volta contra toda sabedoria.'),
('Proverbs 18:2','O tolo não tem prazer no entendimento, mas sim em revelar sua própria opinião.'),
('Proverbs 18:3','Na vinda do perverso, vem também o desprezo; e com a desonra vem a vergonha.'),
('Proverbs 18:4','A boca do homem são como águas profundas; e o manancial de sabedoria como um ribeiro transbordante.'),
('Proverbs 18:5','Não é bom favorecer ao perverso para prejudicar ao justo num julgamento.'),
('Proverbs 18:6','Os lábios do tolo entram em briga, e sua boca chama pancadas.'),
('Proverbs 18:7','A boca do tolo é sua própria destruição, e seus lábios são armadilha para sua alma.'),
('Proverbs 18:8','As palavras do fofoqueiro são como alimentos deliciosos,  que descem até o interior do ventre.'),
('Proverbs 18:9','O preguiçoso em fazer sua obra é irmão do causador de prejuízo.'),
('Proverbs 18:10','O nome do SENHOR é uma torre forte; o justo correrá até ele, e ficará seguro.'),
('Proverbs 18:11','Os bens do rico são como uma cidade fortificada, e como um muro alto em sua imaginação.'),
('Proverbs 18:12','Antes da ruína o coração humano é orgulhoso; e antes da honra vem a humildade.'),
('Proverbs 18:13','Quem responde antes de ouvir age como tolo e causa vergonha para si.'),
('Proverbs 18:14','O espírito do homem o sustentará quando doente; mas o espírito abatido, quem o levantará?'),
('Proverbs 18:15','O coração do prudente adquire conhecimento; e o ouvido dos sábios busca conhecimento.'),
('Proverbs 18:16','O presente do homem alarga seu caminho, e o leva perante a face dos grandes.'),
('Proverbs 18:17','Aquele que primeiro mostra sua causa parece ser justo; mas somente até que outro venha, e o investigue.'),
('Proverbs 18:18','O sorteio cessa disputas, e separa poderosos de se confrontarem .'),
('Proverbs 18:19','O irmão ofendido é mais difícil que uma cidade fortificada; e as brigas são como ferrolhos de uma fortaleza.'),
('Proverbs 18:20','Do fruto da boca do homem seu ventre se fartará; dos produtos de seus lábios se saciará.'),
('Proverbs 18:21','A morte e a vida estão no poder da língua; e aquele que a ama comerá do fruto dela.'),
('Proverbs 18:22','Quem encontrou esposa, encontrou o bem; e obteve o favor do SENHOR.'),
('Proverbs 18:23','O pobre fala com súplicas; mas o rico responde com durezas.'),
('Proverbs 18:24','O homem que tem amigos pode ser prejudicado por eles ; porém há um amigo mais chegado que um irmão.'),
('Proverbs 19:1','Melhor é o pobre que anda em sua honestidade do que o perverso de lábios e tolo.'),
('Proverbs 19:2','E não é bom a alma sem conhecimento; e quem tem pés apressados comete erros.'),
('Proverbs 19:3','A loucura do homem perverte seu caminho; e seu coração se ira contra o SENHOR.'),
('Proverbs 19:4','A riqueza faz ganhar muitos amigos; mas ao pobre, até seu amigo o abandona.'),
('Proverbs 19:5','A falsa testemunha não ficará impune; e quem fala mentiras não escapará.'),
('Proverbs 19:6','Muitos suplicam perante o príncipe; e todos querem ser amigos daquele que dá presentes.'),
('Proverbs 19:7','Todos os irmãos do pobre o odeiam; ainda mais seus amigos se afastam dele; ele corre atrás deles com palavras, mas eles nada lhe respondem .'),
('Proverbs 19:8','Quem adquire entendimento ama sua alma; quem guarda a prudência encontrará o bem.'),
('Proverbs 19:9','A falsa testemunha não ficará impune; e quem fala mentiras perecerá.'),
('Proverbs 19:10','O luxo não é adequado ao tolo; muito menos ao servo dominar sobre príncipes.'),
('Proverbs 19:11','A prudência do homem retém sua ira; e sua glória é ignorar a ofensa.'),
('Proverbs 19:12','A fúria do rei é como o rugido de um leão; mas seu favor é como orvalho sobre a erva.'),
('Proverbs 19:13','O filho tolo é uma desgraça ao seu pai; e brigas da esposa são como uma goteira duradoura.'),
('Proverbs 19:14','A casa e as riquezas são a herança dos pais; porém a mulher prudente vem do SENHOR.'),
('Proverbs 19:15','A preguiça faz cair num sono profundo; e a alma desocupada passará fome.'),
('Proverbs 19:16','Quem guarda o mandamento cuida de sua alma; e quem despreza seus caminhos morrerá.'),
('Proverbs 19:17','Quem faz misericórdia ao pobre empresta ao SENHOR; e ele lhe pagará sua recompensa.'),
('Proverbs 19:18','Castiga a teu filho enquanto há esperança; mas não levantes tua alma para o matar.'),
('Proverbs 19:19','Aquele que tem grande irá será punido; porque se tu o livrares, terás de fazer o mesmo de novo.'),
('Proverbs 19:20','Ouve o conselho, e recebe a disciplina; para que sejas sábio nos teus últimos dias .'),
('Proverbs 19:21','Há muitos pensamentos no coração do homem; porém o conselho do SENHOR prevalecerá.'),
('Proverbs 19:22','O que se deseja do homem é sua bondade; porém o pobre é melhor do que o homem mentiroso.'),
('Proverbs 19:23','O temor ao SENHOR encaminha para a vida; aquele que o tem habitará satisfeito, nem mal algum o visitará.'),
('Proverbs 19:24','O preguiçoso põe sua mão no prato, e nem sequer a leva de volta à boca.'),
('Proverbs 19:25','Fere ao zombador, e o ingênuo será precavido; e repreende ao prudente, e ele aprenderá conhecimento.'),
('Proverbs 19:26','Aquele que prejudica ao pai ou afugenta a mãe é filho causador de vergonha e de desgraça.'),
('Proverbs 19:27','Filho meu, deixa de ouvir a instrução, então te desviarás das palavras de conhecimento.'),
('Proverbs 19:28','A má testemunha escarnece do juízo; e a boca dos perversos engole injustiça.'),
('Proverbs 19:29','Julgamentos estão preparados para zombadores, e açoites para as costas dos tolos.'),
('Proverbs 20:1','O vinho é zombador, a bebida forte é causadora de alvoroços; e todo aquele que errar por causa deles não é sábio.'),
('Proverbs 20:2','O temor ao rei é como um rugido de leão; e quem se ira contra ele peca contra sua própria alma.'),
('Proverbs 20:3','É honroso ao homem terminar a disputa; mas todo tolo nela se envolve.'),
('Proverbs 20:4','O preguiçoso não lavra no inverno; por isso ele mendigará durante a ceifa, pois nada terá.'),
('Proverbs 20:5','O conselho no coração do homem é como águas profundas; mas o homem prudente consegue tirá-lo para fora.'),
('Proverbs 20:6','Muitos homens, cada um deles afirma ter bondade; porém o homem fiel, quem o encontrará?'),
('Proverbs 20:7','O justo caminha em sua integridade; bem-aventurados serão seus filhos depois dele.'),
('Proverbs 20:8','O rei, ao se sentar no trono do juízo, com seus olhos dissipa todo mal.'),
('Proverbs 20:9','Quem poderá dizer: “Purifiquei meu coração; estou limpo de meu pecado”?'),
('Proverbs 20:10','Dois pesos e duas medidas, ambos são abominação ao SENHOR.'),
('Proverbs 20:11','Até o jovem é conhecido pelas suas ações, se sua obra for pura e correta.'),
('Proverbs 20:12','O ouvido que ouve e o olho que vê, o SENHOR os fez ambos.'),
('Proverbs 20:13','Não ames ao sono, para que não empobreças; abre teus olhos, e te fartarás de pão.'),
('Proverbs 20:14','Preço ruim, preço ruim, diz o comprador; mas quando vai embora, então se gaba.'),
('Proverbs 20:15','Há ouro, e muitos rubis; mas os lábios do conhecimento são joia preciosa.'),
('Proverbs 20:16','Toma a roupa daquele que fica por fiador de estranho; toma como penhor daquele que fica por fiador da estranha.'),
('Proverbs 20:17','O pão da mentira é agradável ao homem; mas depois sua boca se encherá de pedregulhos.'),
('Proverbs 20:18','Os planos são confirmados por meio do conselho; e com conselhos prudentes faze a guerra.'),
('Proverbs 20:19','Quem anda fofocando revela segredos; por isso não te envolvas com aquele que fala demais com seus lábios.'),
('Proverbs 20:20','Aquele que amaldiçoar a seu pai ou a sua mãe terá sua lâmpada apagada em trevas profundas.'),
('Proverbs 20:21','A herança ganha apressadamente no princípio, seu fim não será abençoado.'),
('Proverbs 20:22','Não digas: Devolverei o mal; Espera pelo SENHOR, e ele te livrará.'),
('Proverbs 20:23','O SENHOR abomina pesos falsificados; e balanças enganosas não são boas.'),
('Proverbs 20:24','Os passos do homem pertencem ao SENHOR; como, pois, o homem entenderá seu caminho?'),
('Proverbs 20:25','Armadilha ao homem é prometer precipitadamente algo como sagrado, e somente depois pensar na seriedade dos votos que fez .'),
('Proverbs 20:26','O rei sábio espalha os perversos, e os atropela.'),
('Proverbs 20:27','O espírito humano é uma lâmpada do SENHOR, que examina todo o interior do ventre.'),
('Proverbs 20:28','A bondade e a fidelidade protegem o rei; e com bondade seu trono é sustentado.'),
('Proverbs 20:29','A beleza dos jovens é sua força; e a honra dos velhos é seus cabelos brancos.'),
('Proverbs 20:30','Os golpes das feridas purificam os maus; como também as pancadas no interior do corpo.'),
('Proverbs 21:1','Como ribeiros de águas é o coração do rei na mão do SENHOR, ele o conduz para onde quer.'),
('Proverbs 21:2','Todo caminho do homem é correto aos seus próprios olhos; mas o SENHOR pesa os corações.'),
('Proverbs 21:3','Praticar justiça e juízo é mais aceitável ao SENHOR do que sacrifício.'),
('Proverbs 21:4','Olhos orgulhosos e coração arrogante: a lavoura dos perversos é pecado.'),
('Proverbs 21:5','Os planos de quem trabalha com empenho somente levam à abundância; mas os de todo apressado somente à pobreza.'),
('Proverbs 21:6','Trabalhar para obter tesouros com língua mentirosa é algo inútil e fácil de se perder; os que assim fazem buscam a morte.'),
('Proverbs 21:7','A violência praticada pelos perversos os destruirá, porque se negam a fazer o que é justo.'),
('Proverbs 21:8','O caminho do homem transgressor é problemático; porém a obra do puro é correta.'),
('Proverbs 21:9','É melhor morar num canto do terraço do que numa casa espaçosa com uma mulher briguenta.'),
('Proverbs 21:10','A alma do perverso deseja o mal; seu próximo não lhe agrada em seus olhos.'),
('Proverbs 21:11','Castigando ao zombador, o ingênuo se torna sábio; e ensinando ao sábio, ele ganha conhecimento.'),
('Proverbs 21:12','O justo considera prudentemente a casa do perverso; ele transtorna os perversos para a ruína.'),
('Proverbs 21:13','Quem tapa seu ouvido ao clamor do pobre, ele também clamará, mas não será ouvido.'),
('Proverbs 21:14','O presente em segredo extingue a ira; e a dádiva no colo acalma o forte furor.'),
('Proverbs 21:15','Alegria para o justo é fazer justiça; mas isso é pavor para os que praticam maldade.'),
('Proverbs 21:16','O homem que se afasta do caminho do entendimento repousará no ajuntamento dos mortos.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 21:17','Quem ama o prazer sofrerá necessidade; aquele que ama o vinho e o azeite nunca enriquecerá.'),
('Proverbs 21:18','O resgate em troca do justo é o perverso; e no lugar do reto fica o transgressor.'),
('Proverbs 21:19','É melhor morar em terra deserta do que com uma mulher briguenta e que se irrita facilmente.'),
('Proverbs 21:20','Há tesouro desejável e azeite na casa do sábio; mas o homem tolo é devorador.'),
('Proverbs 21:21','Quem segue a justiça e a bondade achará vida, justiça e honra.'),
('Proverbs 21:22','O sábio passa por cima da cidade dos fortes e derruba a fortaleza em que confiam.'),
('Proverbs 21:23','Quem guarda sua boca e sua língua guarda sua alma de angústias.'),
('Proverbs 21:24','“Zombador” é o nome do arrogante e orgulhoso; ele trata os outros com uma arrogância irritante.'),
('Proverbs 21:25','O desejo do preguiçoso o matará, porque suas mãos se recusam a trabalhar;'),
('Proverbs 21:26','Ele fica desejando suas cobiças o dia todo; mas o justo dá, e não deixa de dar.'),
('Proverbs 21:27','O sacrifício dos perversos é abominável; quanto mais quando a oferta é feita com má intenção.'),
('Proverbs 21:28','A testemunha mentirosa perecerá; porém o homem que ouve a verdade falará com sucesso.'),
('Proverbs 21:29','O homem perverso endurece seu rosto, mas o correto confirma o seu caminho.'),
('Proverbs 21:30','Não há sabedoria, nem entendimento, nem conselho contra o SENHOR.'),
('Proverbs 21:31','O cavalo é preparado para o dia da batalha, mas a vitória vem do SENHOR.'),
('Proverbs 22:1','É preferível ter um bom nome do que muitas riquezas; e ser favorecido é melhor que a prata e o o ouro.'),
('Proverbs 22:2','O rico e o pobre se encontram; todos eles foram feitos pelo SENHOR.'),
('Proverbs 22:3','O prudente vê o mal, e se esconde; mas os ingênuos passam e sofrem as consequências.'),
('Proverbs 22:4','A recompensa da humildade e do temor ao SENHOR são riquezas, honra, e vida.'),
('Proverbs 22:5','Há espinhos e ciladas no caminho do perverso; quem cuida de sua alma deve ficar longe de tal caminho .'),
('Proverbs 22:6','Instrui ao menino em seu caminho, e até quando envelhecer, não se desviará dele.'),
('Proverbs 22:7','O rico domina sobre os pobres, e quem toma emprestado é servo daquele que empresta.'),
('Proverbs 22:8','Aquele que semeia perversidade colherá sofrimento; e a vara de sua ira se acabará.'),
('Proverbs 22:9','Quem tem olhos bondosos será abençoado, porque deu de seu pão ao pobre.'),
('Proverbs 22:10','Expulsa ao zombador, e a briga terminará; cessará a disputa e a vergonha.'),
('Proverbs 22:11','Quem ama a pureza do coração fala graciosamente com os lábios, e o rei será seu amigo.'),
('Proverbs 22:12','Os olhos do SENHOR protegem o conhecimento; porém ele transtornará as palavras do enganador.'),
('Proverbs 22:13','O preguiçoso diz: Há um leão lá fora! Ele me matará nas ruas!'),
('Proverbs 22:14','A boca da mulher pervertida é uma cova profunda; aquele contra quem o SENHOR se irar cairá nela.'),
('Proverbs 22:15','A tolice está amarrada ao coração do menino; mas a vara da correção a mandará para longe dele.'),
('Proverbs 22:16','Aquele que oprime ao pobre para proveito próprio e aquele que dá suborno ao rico certamente empobrecerão.'),
('Proverbs 22:17','Inclina o teu ouvido e escuta as palavras dos sábios; dispõe teu coração ao meu conhecimento;'),
('Proverbs 22:18','porque é agradável que as guardes dentro de ti, e estejam prontas para os teus lábios;'),
('Proverbs 22:19','para que tua confiança esteja no SENHOR, eu as ensino a ti hoje.'),
('Proverbs 22:20','Por acaso não te escrevi excelentes  coisas sobre o conselho e o conhecimento,'),
('Proverbs 22:21','para te ensinar a certeza das palavras da verdade, para que possas responder palavras de verdade aos que te enviarem?'),
('Proverbs 22:22','Não roubes ao pobre, porque ele é pobre; nem oprimas ao aflito junto à porta do julgamento.'),
('Proverbs 22:23','Porque o SENHOR defenderá a causa deles em juízo, e quanto aos que os roubam, ele lhes roubará a alma.'),
('Proverbs 22:24','Não seja companheiro de quem se irrita facilmente, nem andes com o homem furioso,'),
('Proverbs 22:25','Para que não aprendas o caminho dele, e te ponhas em armadilhas para tua alma.'),
('Proverbs 22:26','Não estejas entre os que se comprometem em acordos com as mãos, ou os que ficam por fiadores de dívidas.'),
('Proverbs 22:27','Se não tens como pagar, por que razão tirariam tua cama debaixo de ti?'),
('Proverbs 22:28','Não mudes os limites antigos que teus pais fizeram.'),
('Proverbs 22:29','Viste um homem habilidoso em sua obra? Perante a face dos reis ele será posto; ele não será posto diante de pessoas sem honra.'),
('Proverbs 23:1','Quando te sentares para comer com algum dominador, presta muita atenção para o que estiver diante de ti;'),
('Proverbs 23:2','E põe uma faca à tua garganta, se tiveres muito apetite.'),
('Proverbs 23:3','Não desejes as comidas gostosas dele, porque são pão de mentiras.'),
('Proverbs 23:4','Não trabalhes exaustivamente para ser rico; modera-te por meio de tua prudência.'),
('Proverbs 23:5','Porás teus olhos fixos sobre aquilo que é nada? Porque certamente se fará asas, e voará ao céu como uma águia.'),
('Proverbs 23:6','Não comas o pão de quem tem olho maligno, nem cobices suas comidas gostosas.'),
('Proverbs 23:7','Porque ele calcula seus gastos consigo mesmo. Assim ele dirá: Come e bebe; Mas o coração dele não está contigo;'),
('Proverbs 23:8','Vomitarias o pedaço que comeste, e perderias tuas palavras agradáveis.'),
('Proverbs 23:9','Não fales aos ouvidos do tolo, porque ele desprezará a prudência de tuas palavras.'),
('Proverbs 23:10','Não mudes os limites antigos, nem ultrapasses as propriedades dos órfãos;'),
('Proverbs 23:11','Porque o Defensor deles é poderoso; ele disputará a causa deles contra ti.'),
('Proverbs 23:12','Aplica teu coração à disciplina, e teus ouvidos às palavras de conhecimento.'),
('Proverbs 23:13','Não retires a disciplina do jovem; quando o bateres com a vara, nem por isso morrerá.'),
('Proverbs 23:14','Tu o baterás com a vara, e livrarás a alma dele do mundo dos mortos.'),
('Proverbs 23:15','Meu filho, se teu coração for sábio, meu coração se alegrará, e eu também.'),
('Proverbs 23:16','Meu interior saltará de alegria quando teus lábios falarem coisas corretas.'),
('Proverbs 23:17','Teu coração não inveje aos pecadores; porém permanece no temor ao SENHOR o dia todo;'),
('Proverbs 23:18','Porque certamente há um bom futuro para ti , e tua expectativa não será cortada.'),
('Proverbs 23:19','Ouve, filho meu, e sê sábio; e conduz teu coração no caminho correto .'),
('Proverbs 23:20','Não esteja entre os beberrões de vinho, nem entre os comilões de carne.'),
('Proverbs 23:21','Porque o beberrão e o comilão empobrecerão; e a sonolência os faz vestir trapos.'),
('Proverbs 23:22','Ouve a teu pai, que te gerou; e não desprezes a tua mãe, quando ela envelhecer.'),
('Proverbs 23:23','Compra a verdade, e não a vendas; faze o mesmo com a sabedoria, a disciplina e a prudência.'),
('Proverbs 23:24','O pai do justo muito se alegrará; aquele que gerar o sábio se encherá de alegria por causa dele.'),
('Proverbs 23:25','Teu pai e tua mãe se alegrarão; aquela te te gerou se encherá de alegria.'),
('Proverbs 23:26','Meu filho, dá para mim teu coração, e que teus olhos prestem atenção em meus caminhos.'),
('Proverbs 23:27','Porque a prostituta é como uma cova profunda, e a estranha como um poço estreito.'),
('Proverbs 23:28','Também ela fica espreitando como um ladrão, e acrescenta transgressores entre os homens.'),
('Proverbs 23:29','De quem são os ais? De quem são os sofrimentos? De quem são as lutas? De quem são as queixas? De quem são as feridas desnecessárias? De quem são os olhos vermelhos?'),
('Proverbs 23:30','São daqueles que gastam tempo junto ao vinho, daqueles que andam em busca da bebida misturada.'),
('Proverbs 23:31','Não prestes atenção ao vinho quando se mostra vermelho, quando brilha no copo e escorre suavemente,'),
('Proverbs 23:32','Pois seu fim é como mordida de cobra, e picará como uma víbora.'),
('Proverbs 23:33','Teus olhos verão coisas estranhas, e teu coração falará perversidades;'),
('Proverbs 23:34','E serás como o que dorme no meio do mar, e como o que dorme no topo do mastro.'),
('Proverbs 23:35','E dirás : Espancaram-me, mas não senti dor; bateram em mim, mas não senti; quando virei a despertar? Vou buscar mais uma bebida .'),
('Proverbs 24:1','Não tenhas inveja dos homens malignos, nem desejes estar com eles;'),
('Proverbs 24:2','Porque o coração deles imagina destruição, e os lábios deles falam de opressão.'),
('Proverbs 24:3','Pela sabedoria a casa é edificada, e pelo entendimento ela fica firme;'),
('Proverbs 24:4','E pelo conhecimento os cômodos se encherão de riquezas preciosas e agradáveis.'),
('Proverbs 24:5','O homem sábio é poderoso; e o homem que tem conhecimento aumenta sua força;'),
('Proverbs 24:6','Porque com conselhos prudentes farás tua guerra; e a vitória é alcançada pela abundância de conselheiros.'),
('Proverbs 24:7','A sabedoria é alta demais para o tolo; na porta do julgamento ele não abre sua boca.'),
('Proverbs 24:8','Quem planeja fazer o mal será chamado de vilão.'),
('Proverbs 24:9','O pensamento do tolo é pecado; e o zombador é abominável aos homens.'),
('Proverbs 24:10','Se te mostrares fraco no dia da angústia, como é pouca tua força!'),
('Proverbs 24:11','Livra os que estão tomados para a morte, os que estão sendo levados para serem mortos;'),
('Proverbs 24:12','Pois se tu disseres: Eis que não sabíamos,Por acaso aquele que pesa os corações não saberá? Aquele que guarda tua alma não conhecerá? Ele retribuirá ao homem conforme sua obra.'),
('Proverbs 24:13','Come mel, meu filho, porque é bom; e o favo de mel é doce ao teu paladar.'),
('Proverbs 24:14','Assim será o conhecimento da sabedoria para tua alma; se a encontrares haverá recompensa para ti ; e tua esperança não será cortada.'),
('Proverbs 24:15','Tu, perverso, não espies a habitação do justo, nem assoles seu quarto;'),
('Proverbs 24:16','Porque o justo cai sete vezes, e se levanta; mas os perversos tropeçam no mal.'),
('Proverbs 24:17','Quando teu inimigo cair, não te alegres; nem teu coração fique contente quando ele tropeçar,'),
('Proverbs 24:18','Para que não aconteça de o SENHOR veja, e o desagrade, e desvie dele sua ira.'),
('Proverbs 24:19','Não te irrites com os malfeitores, nem tenhas inveja dos perversos;'),
('Proverbs 24:20','Porque o maligno não terá um bom futuro; a lâmpada dos perversos se apagará.'),
('Proverbs 24:21','Meu filho, teme ao SENHRO e ao rei; e não te envolvas com os rebeldes;');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 24:22','Porque a destruição deles se levantará de repente; e quem sabe que ruína eles terão?'),
('Proverbs 24:23','Estes provérbios também são para os sábios: fazer acepção de pessoas num julgamento não é bom.'),
('Proverbs 24:24','Aquele que disser ao ímpio: Tu és justo,Os povos o amaldiçoarão, as nações o detestarão.'),
('Proverbs 24:25','Mas para aqueles que o repreenderem, haverá coisas boas; e sobre eles virá uma boa bênção.'),
('Proverbs 24:26','Quem responde palavras corretas é como se estivesse beijando com os lábios.'),
('Proverbs 24:27','Prepara tua obra de fora, e a deixa pronta no campo; somente depois edifica tua casa.'),
('Proverbs 24:28','Não sejas testemunha contra teu próximo sem causa; por que enganarias com teus lábios?'),
('Proverbs 24:29','Não digas: Assim como ele fez a mim, assim também farei a ele; pagarei a cada um conforme sua obra.'),
('Proverbs 24:30','Passei junto ao campo do preguiçoso, e junto à vinha do homem sem juízo;'),
('Proverbs 24:31','E eis que ela estava toda cheia de espinheiros, e sua superfície coberta de urtigas; e sua cerca de pedra estava derrubada.'),
('Proverbs 24:32','Quando eu a vi, aprendi em meu coração, e ao olhá -la ,recebi instrução:'),
('Proverbs 24:33','Um pouco de sono, cochilando um pouco, cruzando as mãos por um pouco de tempo deitado,'),
('Proverbs 24:34','E assim tua pobreza virá como um assaltante; tua necessidade chegará como um homem armado.'),
('Proverbs 25:1','Estes também são provérbios de Salomão, que foram copiados pelos homens de Ezequias, rei de Judá.'),
('Proverbs 25:2','É glória de Deus encobrir alguma coisa; mas a glória dos Reis é investigá-la.'),
('Proverbs 25:3','Para a altura dos céus, para a profundeza da terra, assim como para o coração dos reis, não há como serem investigados.'),
('Proverbs 25:4','Tira as escórias da prata, e sairá um vaso para o fundidor.'),
('Proverbs 25:5','Tira o perverso de diante do rei, e seu trono se firmará com justiça.'),
('Proverbs 25:6','Não honres a ti mesmo perante o rei, nem te ponhas no lugar dos grandes;'),
('Proverbs 25:7','Porque é melhor que te digam: Sobe aqui;Do que te rebaixem perante a face do príncipe, a quem teus olhos viram.'),
('Proverbs 25:8','Não sejas apressado para entrar numa disputa; senão, o que farás se no fim teu próximo te envergonhar?'),
('Proverbs 25:9','Disputa tua causa com teu próximo, mas não reveles segredo de outra pessoa.'),
('Proverbs 25:10','Para que não te envergonhe aquele que ouvir; pois tua má fama não pode ser desfeita.'),
('Proverbs 25:11','A palavra dita em tempo apropriado é como maçãs de ouro em bandejas de prata.'),
('Proverbs 25:12','O sábio que repreende junto a um ouvido disposto a escutar é como pendentes de ouro e ornamentos de ouro refinado.'),
('Proverbs 25:13','Como frio de neve no tempo da colheita, assim é o mensageiro fiel para aqueles que o enviam; porque ele refresca a alma de seus senhores.'),
('Proverbs 25:14','Como nuvens e ventos que não trazem chuva, assim é o homem que se orgulha de falsos presentes.'),
('Proverbs 25:15','Com paciência para não se irar é que se convence um líder; e a língua suave quebra ossos.'),
('Proverbs 25:16','Achaste mel? Come o que te for suficiente; para que não venhas a ficar cheio demais, e vomites.'),
('Proverbs 25:17','Não exagere teus pés na casa de teu próximo, para que ele não se canse de ti, e te odeie.'),
('Proverbs 25:18','Martelo, espada e flecha afiada é o homem que fala falso testemunho contra seu próximo.'),
('Proverbs 25:19','Confiar num infiel no tempo de angústia é como um dente quebrado ou um pé sem firmeza.'),
('Proverbs 25:20','Quem canta canções ao coração aflito é como aquele que tira a roupa num dia frio, ou como vinagre sobre salitre.'),
('Proverbs 25:21','Se aquele que te odeia tiver fome, dá-lhe pão para comer; e se tiver sede, dá-lhe água para beber;'),
('Proverbs 25:22','Porque assim amontoarás brasas sobre a cabeça dele, e o SENHOR te recompensará.'),
('Proverbs 25:23','O vento norte traz a chuva; assim como a língua caluniadora traz a ira no rosto.'),
('Proverbs 25:24','É melhor morar num canto do terraço do que com uma mulher briguenta numa casa espaçosa.'),
('Proverbs 25:25','Como água refrescante para a alma cansada, assim são boas notícias de uma terra distante.'),
('Proverbs 25:26','O justo que se deixa levar pelo perverso é como uma fonte turva e um manancial poluído.'),
('Proverbs 25:27','Comer muito mel não é bom; assim como buscar muita glória para si.'),
('Proverbs 25:28','O homem que não pode conter seu espírito é como uma cidade derrubada sem muro.'),
('Proverbs 26:1','Assim como a neve no verão, como a chuva na colheita, assim também não convém a honra para o tolo.'),
('Proverbs 26:2','Como um pássaro a vaguear, como a andorinha a voar, assim também a maldição não virá sem causa.'),
('Proverbs 26:3','Açoite para o cavalo, cabresto para o asno; e vara para as costas dos tolos.'),
('Proverbs 26:4','Não respondas ao tolo conforme sua loucura; para que não te faças semelhante a ele.'),
('Proverbs 26:5','Responde ao tolo conforme sua loucura, para que ele não seja sábio aos seus próprios olhos.'),
('Proverbs 26:6','Quem manda mensagens pelas mãos do tolo é como quem corta os pés e bebe violência.'),
('Proverbs 26:7','Assim como não funcionam as pernas do aleijado, assim também é o provérbio na boca dos tolos.'),
('Proverbs 26:8','Dar honra ao tolo é como amarrar uma pedra numa funda.'),
('Proverbs 26:9','Como espinho na mão do bêbado, assim é o provérbio na boca dos tolos.'),
('Proverbs 26:10','Como um flecheiro que atira para todo lado, assim é aquele que contrata um tolo ou que contrata alguém que vai passando.'),
('Proverbs 26:11','Como um cão que volta a seu vômito, assim é o tolo que repete sua loucura.'),
('Proverbs 26:12','Viste algum homem sábio aos seus próprios olhos? Mais esperança há para o tolo do que para ele.'),
('Proverbs 26:13','O preguiçoso diz: Há uma fera no caminho; há um leão nas ruas.'),
('Proverbs 26:14','Como a porta se vira em torno de suas dobradiças, assim o preguiçoso se vira em sua cama.'),
('Proverbs 26:15','O preguiçoso põe sua mão no prato, e acha cansativo demais trazê-la de volta a sua boca.'),
('Proverbs 26:16','O preguiçoso se acha mais sábio aos próprios olhos do que sete que respondem com prudência.'),
('Proverbs 26:17','Aquele que, enquanto está passando, se envolve em briga que não é sua, é como o que pega um cão pelas orelhas.'),
('Proverbs 26:18','Como o louco que lança faíscas, flechas e coisas mortíferas,'),
('Proverbs 26:19','Assim é o homem que engana a seu próximo, e diz: Não estava eu só brincando?'),
('Proverbs 26:20','Sem lenha, o fogo se apaga; e sem fofoqueiro, a briga termina.'),
('Proverbs 26:21','O carvão é para as brasas, e a lenha para o fogo; e o homem difamador para acender brigas.'),
('Proverbs 26:22','As palavras do fofoqueiro são como alimentos deliciosos,  que descem ao interior do ventre.'),
('Proverbs 26:23','Como um vaso de fundição coberto de restos de prata, assim são os lábios inflamados e o coração maligno.'),
('Proverbs 26:24','Aquele que odeia dissimula em seus lábios, mas seu interior abriga o engano;'),
('Proverbs 26:25','Quando ele te falar agradavelmente com sua voz, não acredites nele; porque há sete abominações em seu coração;'),
('Proverbs 26:26','Cujo ódio está encoberto pelo engano; sua maldade será descoberta na congregação.'),
('Proverbs 26:27','Quem cava uma cova, nela cairá; e quem rola uma pedra, esta voltará sobre ele.'),
('Proverbs 26:28','A língua falsa odeia aos que ela atormenta; e a boca lisonjeira opera ruína.'),
('Proverbs 27:1','Não te orgulhes do dia de amanhã; porque não sabes o que o dia trará.'),
('Proverbs 27:2','Que o estranho te louve, e não tua própria boca; o estrangeiro, e não teus próprios lábios.'),
('Proverbs 27:3','A pedra é pesada, e a areia tem seu peso; mas a provocação do tolo é mais pesada do que estas ambas.'),
('Proverbs 27:4','O furor é cruel, e a ira impetuosa; mas quem resistirá firme perante à inveja?'),
('Proverbs 27:5','Melhor é a repreensão clara do que o amor escondido.'),
('Proverbs 27:6','Fiéis são as feridas feitas por um amigo, mas os beijos de um inimigo são enganosos.'),
('Proverbs 27:7','A alma saciada rejeita  o favo de mel; mas para a alma faminta, toda coisa amarga é doce.'),
('Proverbs 27:8','Como a ave, que vagueia de seu ninho, assim é o homem que anda vagueando de seu lugar.'),
('Proverbs 27:9','O óleo e o perfume alegram ao coração; assim é a doçura de um amigo com um conselho sincero.'),
('Proverbs 27:10','Não abandones o teu amigo, nem o amigo de teu pai; nem entres na casa de teu irmão no dia de tua adversidade; melhor é o vizinho que está perto do que o irmão que está longe.'),
('Proverbs 27:11','Sê sábio, meu filho, e alegra meu coração; para que eu tenha algo a responder para aquele que me desprezar.'),
('Proverbs 27:12','O prudente vê o mal, e se esconde; mas os ingênuos passam adiante, e sofrem as consequências.'),
('Proverbs 27:13','Toma a roupa daquele que fica por fiador de estranho; toma penhor daquele que fica por fiador da estranha.'),
('Proverbs 27:14','Aquele que bendiz ao seu amigo em alta voz durante a madrugada lhe será considerado como maldição.'),
('Proverbs 27:15','A mulher briguenta é semelhante a uma goteira contínua em tempo de grande chuva;'),
('Proverbs 27:16','Tentar contê-la é como tentar conter o vento, ou impedir que o óleo escorra de sua mão direita.'),
('Proverbs 27:17','O ferro é afiado com ferro; assim também o homem afia o rosto de seu amigo.'),
('Proverbs 27:18','Aquele que guarda a figueira comerá de seu fruto; e o que dá atenção ao seu senhor será honrado.'),
('Proverbs 27:19','Assim como a água reflete o rosto, assim também o coração reflete o ser humano.'),
('Proverbs 27:20','O mundo dos mortos e a destruição nunca estão fartos; assim também os olhos do homem nunca estão satisfeitos.'),
('Proverbs 27:21','Como o crisol é para a prata, e o forno para o ouro, assim o homem é provado pelos louvores que lhe dizem.'),
('Proverbs 27:22','Ainda que esmagues ao tolo em um pilão junto com os grãos, ainda assim sua loucura não se separaria dele.'),
('Proverbs 27:23','Procura conhecer a condição de tuas ovelhas; põe teu coração sobre o gado;'),
('Proverbs 27:24','porque o tesouro não dura para sempre; nem uma coroa dura de geração em geração.'),
('Proverbs 27:25','Quando a erva aparecer, e surgirem a folhagem, e se juntarem as ervas dos montes,'),
('Proverbs 27:26','Os cordeiros serão para tuas roupas, e os bodes para o preço do campo;'),
('Proverbs 27:27','E o leite das cabras será o suficiente para tua alimentação, para a alimentação de tua casa, e para o sustento de tuas servas.'),
('Proverbs 28:1','Os perversos fogem mesmo quando não há quem os persiga, mas os justos são confiantes como um leão.'),
('Proverbs 28:2','Pela rebelião numa terra, seus governantes são muitos; mas por meio de um homem prudente e conhecedor seu governo permanecerá.'),
('Proverbs 28:3','O homem pobre que oprime aos necessitados é como uma chuva devastadora que causa falta de pão.'),
('Proverbs 28:4','Os que abandonam a lei louvam ao perverso; porém os que guardam a lei lutarão contra eles.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 28:5','Os homens maus não entendem a justiça; mas os que buscam ao SENHOR entendem tudo.'),
('Proverbs 28:6','Melhor é o pobre que anda em sua honestidade do que o perverso de caminhos, ainda que seja rico.'),
('Proverbs 28:7','O que guarda a lei é um filho prudente, mas o companheiro de comilões envergonha a seu pai.'),
('Proverbs 28:8','Aquele que aumenta seus bens por meio de juros e lucros desonestos está juntando para o que se compadece dos pobres.'),
('Proverbs 28:9','Aquele que desvia seus ouvidos de ouvir a lei, até sua oração será abominável.'),
('Proverbs 28:10','Aquele que faz as pessoas corretas errarem em direção a um mau caminho, ele mesmo cairá em sua cova; mas os que não tiverem pecado herdarão o bem.'),
('Proverbs 28:11','O homem rico é sábio aos seus próprios olhos; mas o pobre prudente o examina.'),
('Proverbs 28:12','Quando os justos estão contentes, muita é a alegria; mas quando os perversos se levantam, os homens se escondem.'),
('Proverbs 28:13','Quem encobre suas transgressões nunca prosperará, mas aquele que as confessa e as abandona alcançará misericórdia.'),
('Proverbs 28:14','Bem-aventurado o homem que sempre mantém seu temor; mas aquele que endurece seu coração cairá no mal.'),
('Proverbs 28:15','Leão rugidor e urso faminto é o governante perverso sobre um povo pobre.'),
('Proverbs 28:16','O príncipe que tem falta de entendimento aumenta as opressões; mas aquele que odeia o lucro desonesto prolongará seus dias.'),
('Proverbs 28:17','O homem atormentado pelo sangue de alguma alma fugirá até a cova; ninguém o detenha.'),
('Proverbs 28:18','Aquele que anda sinceramente será salvo; mas o que se desvia em seus caminhos cairá de uma só vez.'),
('Proverbs 28:19','Aquele que lavrar sua terra terá fartura de pão; mas o que segue coisas inúteis terá fartura de pobreza.'),
('Proverbs 28:20','O homem fiel terá muitas bênçãos; mas o que se apressa para enriquecer não ficará impune.'),
('Proverbs 28:21','Fazer acepção de pessoas não é bom; porque até por um pedaço de pão o homem pode transgredir.'),
('Proverbs 28:22','Quem tem pressa para ter riquezas é um homem de olho mau; e ele não sabe que a miséria virá sobre ele.'),
('Proverbs 28:23','Aquele que repreende ao homem obterá mais favor depois do que aquele que lisonjeia com a língua.'),
('Proverbs 28:24','Aquele que furta seu pai ou sua mãe e diz: Não é pecado,É companheiro do homem destruidor.'),
('Proverbs 28:25','Quem tem alma orgulhosa levanta brigas; mas aquele que confia no SENHOR prosperará.'),
('Proverbs 28:26','Aquele que confia em seu próprio coração é tolo; mas o que anda em sabedoria escapará em segurança .'),
('Proverbs 28:27','Quem dá ao pobre não terá falta; mas o que esconde seus olhos terá muitas maldições.'),
('Proverbs 28:28','Quando os perversos ganham poder, os homens se escondem; mas quando perecem, os justos se multiplicam.'),
('Proverbs 29:1','O homem que age com teimosia,  mesmo depois de muitas repreensões, será tão destruído que não terá mais cura.'),
('Proverbs 29:2','Quando os justos se engrandecem, o povo se alegra; mas quando o perverso domina, o povo geme.'),
('Proverbs 29:3','O homem que ama a sabedoria alegra a seu pai; mas o companheiro de prostitutas gasta os bens.'),
('Proverbs 29:4','O rei por meio da justiça firma a terra; mas o amigo de subornos a transtorna.'),
('Proverbs 29:5','O homem que lisonjeia a seu próximo arma uma rede para seus pés.'),
('Proverbs 29:6','Na transgressão do homem mau há uma armadilha; mas o justo se alegra e se enche de alegria.'),
('Proverbs 29:7','O justo considera a causa judicial dos pobres; mas o perverso não entende este conhecimento.'),
('Proverbs 29:8','Homens zombadores trazem confusão a cidade; mas os sábios desviam a ira.'),
('Proverbs 29:9','O homem sábio que disputa no julgamento contra um tolo, mesmo se perturbado ou rindo, não terá descanso.'),
('Proverbs 29:10','Homens sanguinários odeiam o honesto; mas os corretos procuram o seu bem.'),
('Proverbs 29:11','O louco mostra todo o seu ímpeto; mas o sábio o mantém sob controle.'),
('Proverbs 29:12','O governante que dá atenção a palavras mentirosas, todos os seus servos serão perversos.'),
('Proverbs 29:13','O pobre e o enganador se encontram: o SENHOR ilumina aos olhos de ambos.'),
('Proverbs 29:14','O rei que julga aos pobres por meio da verdade, seu trono se firmará para sempre.'),
('Proverbs 29:15','A vara e a repreensão dão sabedoria; mas o rapaz deixado solto envergonha a sua mãe.'),
('Proverbs 29:16','Quando os perversos se multiplicam, multiplicam-se as transgressões; mas os justos verão sua queda.'),
('Proverbs 29:17','Castiga a teu filho, e ele te fará descansar, e dará prazeres à tua alma.'),
('Proverbs 29:18','Não havendo visão profética, o povo fica confuso; porém o que guarda a lei, ele é bem-aventurado.'),
('Proverbs 29:19','O servo não será corrigido por meio de palavras; porque ainda que entenda, mesmo assim ele não responderá corretamente .'),
('Proverbs 29:20','Viste um homem precipitado em suas palavras? Mais esperança há para um tolo do que para ele.'),
('Proverbs 29:21','Aquele que mima a seu servo desde a infância, por fim ele quererá ser seu filho.'),
('Proverbs 29:22','O homem que se irrita facilmente levanta brigas; e o furioso multiplica as transgressões.'),
('Proverbs 29:23','A arrogância do homem o abaterá; mas o humilde de espírito obterá honra.'),
('Proverbs 29:24','Aquele que reparte com o ladrão odeia sua própria alma; ele ouve maldições e não o denuncia.'),
('Proverbs 29:25','O temor do homem arma ciladas; mas o que confia no senhor ficará em segurança.'),
('Proverbs 29:26','Muitos buscam a face do governante; mas o julgamento de cada um vem do SENHOR.'),
('Proverbs 29:27','O justos odeiam ao homem perverso; e o injusto odeia aos que andam no caminho correto.'),
('Proverbs 30:1','Palavras de Agur, filho de Jaque, o de fala solene; Este homem diz a Itiel; a Itiel e a Ucal:'),
('Proverbs 30:2','Certamente eu sou o mais bruto dos homens, e não tenho entendimento humano.'),
('Proverbs 30:3','Não aprendi sabedoria, nem tenho conhecimento do Santo Deus .'),
('Proverbs 30:4','Quem subiu ao céu, e desceu? Quem juntou os ventos com suas mãos? Quem amarrou as águas numa capa? Quem estabeleceu todos os limites da terra? Qual é o seu nome? e qual é o nome de seu filho, se tu o sabes?'),
('Proverbs 30:5','Toda palavra de Deus é pura; é escudo para os que nele confiam.'),
('Proverbs 30:6','Nada acrescentes às suas palavras, para que ele não te repreenda, e sejas mostrado como mentiroso.'),
('Proverbs 30:7','Duas coisas eu te pedi; não as negues a mim antes que eu morra.'),
('Proverbs 30:8','Afasta de mim a inutilidade e palavra mentirosa; e não me dês nem pobreza nem riqueza, mantém-me com o pão que me for necessário.'),
('Proverbs 30:9','Para que não aconteça de eu ficar farto e te negar, dizendo: Quem é o SENHOR?Nem também que eu empobreça, e venha a furtar, e desonre o nome do meu Deus.'),
('Proverbs 30:10','Não difames do servo ao seu senhor, para que ele não te amaldiçoe e fiques culpado.'),
('Proverbs 30:11','Há gente que amaldiçoa a seu pai e não bendiz à sua mãe;'),
('Proverbs 30:12','Há gente que é pura aos seus próprios olhos, mas que não foi lavada de sua imundície;'),
('Proverbs 30:13','Há gente cujos olhos são arrogantes, e cujas sobrancelhas são levantadas;'),
('Proverbs 30:14','Há gente cujos dentes são espadas, e cujos queixos são facas, para devorarem aos aflitos da terra aos aflitos, e aos necessitados dentre os homens.'),
('Proverbs 30:15','A sanguessuga tem duas filhas: “Dá” e “Dá”; estas três coisas nunca se fartam, e quatro nunca dizem “É o suficiente”:'),
('Proverbs 30:16','O mundo dos mortos, o ventre feminino estéril, a terra que não se farta de água, e o fogo que nunca diz estar satisfeito.'),
('Proverbs 30:17','Os olhos que zombam do pai ou desprezam obedecer à mãe, os corvos do riacho os arrancarão, e os filhotes de abutre os comerão.'),
('Proverbs 30:18','Estas três coisas me maravilham, e quatro que não entendo:'),
('Proverbs 30:19','O caminho da águia no céu, o caminho da serpente na rocha, o caminho do navio no meio do mar, e o caminho do homem com uma moça.'),
('Proverbs 30:20','Assim é o caminho da mulher adúltera: ela come, limpa sua boca, e diz: Não fiz mal algum.'),
('Proverbs 30:21','Por três coisas a terra se alvoroça, e por quatro que não pode suportar:'),
('Proverbs 30:22','Pelo servo que governa como rei; pelo tolo que se enche de comida;'),
('Proverbs 30:23','Pela mulher odiada, quando se casa; e pela serva quando toma o lugar de sua senhora.'),
('Proverbs 30:24','Estas quatro coisas são pequenas sobre a terra, porém muito sábias:'),
('Proverbs 30:25','As formigas não são criaturas fortes, mas no verão preparam sua comida;'),
('Proverbs 30:26','Os roedores  são um “povo” fraco, mas fazem suas casas nas rochas;'),
('Proverbs 30:27','Os gafanhotos não têm rei; mas todos saem em bandos;'),
('Proverbs 30:28','As lagartixas podem ser pegas com as mãos, e mesmo assim estão nos palácios dos reis.'),
('Proverbs 30:29','Estes três tem um bom andar, e quatro que se movem muito bem:'),
('Proverbs 30:30','O leão, forte entre os animais, que não foge de ninguém;'),
('Proverbs 30:31','O galo, o bode, e o rei com seu exército.'),
('Proverbs 30:32','Se agiste como tolo, exaltando-te, e se planejaste o mal, põe tua mão sobre a boca;'),
('Proverbs 30:33','Porque como o forçar do leite produz manteiga, e o forçar do nariz produz sangue, assim também o forçar da ira produz briga.'),
('Proverbs 31:1','Palavras do rei Lemuel, a profecia que sua mãe o ensinava.'),
('Proverbs 31:2','O que posso te dizer ,meu filho, ó filho do meu ventre? O que te direi ,filho de minhas promessas?'),
('Proverbs 31:3','Não dês tua força às mulheres, nem teus caminhos para coisas que destroem reis.'),
('Proverbs 31:4','Lemuel, não convém aos reis beber vinho; nem aos príncipes desejar bebida alcoólica.'),
('Proverbs 31:5','Para não acontecer de que bebam, e se esqueçam da lei, e pervertam o direito de todos os aflitos.'),
('Proverbs 31:6','Dai bebida alcoólica aos que estão a ponto de morrer, e vinho que têm amargura na alma,'),
('Proverbs 31:7','Para que bebam, e se esqueçam de sua pobreza, e não se lembrem mais de sua miséria.'),
('Proverbs 31:8','Abre tua boca no lugar do mudo pela causa judicial de todos os que estão morrendo.'),
('Proverbs 31:9','Abre tua boca, julga corretamente, e faze justiça aos oprimidos e necessitados.'),
('Proverbs 31:10','Mulher virtuosa, quem a encontrará? Pois seu valor é muito maior que o de rubis.'),
('Proverbs 31:11','O coração de seu marido confia nela, e ele não terá falta de bens.'),
('Proverbs 31:12','Ela lhe faz bem, e não o mal, todos os dias de sua vida.'),
('Proverbs 31:13','Ela busca lã e linho, e com prazer trabalha com suas mãos.'),
('Proverbs 31:14','Ela é como um navio mercante; de longe traz a sua comida.'),
('Proverbs 31:15','Ainda de noite ela se levanta, e dá alimento a sua casa; e ordens às suas servas.'),
('Proverbs 31:16','Ela avalia um campo, e o compra; do fruto de suas mãos planta uma vinha.');
INSERT INTO proverbio (referencia, texto) VALUES
('Proverbs 31:17','Ela prepara seus lombos com vigor, e fortalece seus braços.'),
('Proverbs 31:18','Ela prova que suas mercadorias são boas, e sua lâmpada não se apaga de noite.'),
('Proverbs 31:19','Ela estende suas mãos ao rolo de linha, e com suas mãos prepara os fios.'),
('Proverbs 31:20','Ela estende sua mão ao aflito, e estica os braços aos necessitados.'),
('Proverbs 31:21','Ela não terá medo da neve por sua casa, pois todos os de sua casa estão agasalhados.'),
('Proverbs 31:22','Ela faz cobertas para sua cama; de linho fino e de púrpura é o seu vestido.'),
('Proverbs 31:23','Seu marido é famoso às portas da cidade ,quando ele se senta com os anciãos da terra.'),
('Proverbs 31:24','Ela faz panos de linho fino, e os vende; e fornece cintos aos comerciantes.'),
('Proverbs 31:25','Força e glória são suas roupas, e ela sorri pelo seu futuro.'),
('Proverbs 31:26','Ela abre sua boca com sabedoria; e o ensinamento bondoso está em sua língua.'),
('Proverbs 31:27','Ela presta atenção aos rumos de sua casa, e não come pão da preguiça.'),
('Proverbs 31:28','Seus filhos se levantam e a chamam de bem-aventurada; seu marido também a elogia, dizendo :'),
('Proverbs 31:29','Muitas mulheres agem com virtude, mas tu és melhor que todas elas.'),
('Proverbs 31:30','A beleza é enganosa, e a formosura é passageira; mas a mulher que teme ao SENHOR, essa será louvada.'),
('Proverbs 31:31','Dai a ela conforme o fruto de suas mãos, e que suas obras a louvem às portas da cidade .');